/* CRISC :: content/quiz1.js — CRISC Domain 1 question bank (100 items). */
window.CRISC = window.CRISC || {}; CRISC.questions = CRISC.questions || [];
CRISC.questions.push.apply(CRISC.questions, [
{"id":"D1-001","domain":1,"obj":"1A1","diff":"easy","q":"A risk practitioner is helping define the organization's IT risk strategy. Which of the following should PRIMARILY drive the content of that strategy?","options":["The most recent vulnerability scan report","The enterprise's business objectives and risk appetite","The IT department's annual budget","The number of open audit findings"],"answer":1,"explain":"<strong>The enterprise's business objectives and risk appetite</strong> — an IT risk strategy exists to support what the business is trying to achieve while keeping exposure within the level of risk leadership has agreed to accept.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The most recent vulnerability scan report</b>: this is a narrow technical snapshot, not a basis for enterprise-level risk strategy.</span> <span class='qd'><b>The IT department's annual budget</b>: budget is a resourcing constraint that should follow from strategy, not shape it.</span> <span class='qd'><b>The number of open audit findings</b>: findings are one input but far too limited in scope to define overall strategy.</span>"},
{"id":"D1-002","domain":1,"obj":"1A1","diff":"easy","q":"Which of the following BEST indicates that an organization's risk goals and objectives are effectively cascaded from enterprise strategy?","options":["Each business unit sets its own risk objectives independently","Business unit risk objectives can be traced back to enterprise strategic priorities","Risk objectives are identical across every business unit","Risk objectives are only defined at the IT department level"],"answer":1,"explain":"<strong>Business unit risk objectives can be traced back to enterprise strategic priorities</strong> — effective cascading means lower-level objectives are demonstrably derived from and support the enterprise strategy, creating a coherent line of sight.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Each business unit sets its own risk objectives independently</b>: independence without traceability to enterprise strategy creates fragmentation, not alignment.</span> <span class='qd'><b>Risk objectives are identical across every business unit</b>: uniform objectives ignore that units have different risk profiles and contributions to strategy.</span> <span class='qd'><b>Risk objectives are only defined at the IT department level</b>: risk objectives must span the enterprise, not be confined to a single department.</span>"},
{"id":"D1-003","domain":1,"obj":"1A2","diff":"easy","q":"Which organizational structure characteristic MOST supports effective IT risk governance?","options":["A flat structure with no formal reporting lines","Risk functions reporting solely to the IT help desk","Clearly defined reporting lines that connect risk owners to accountable executives","Structures that change every quarter to stay agile"],"answer":2,"explain":"<strong>Clearly defined reporting lines that connect risk owners to accountable executives</strong> — governance requires an unambiguous path from those who own risk day to day up to the executives and board who are ultimately accountable.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A flat structure with no formal reporting lines</b>: without formal lines, accountability for risk decisions becomes unclear and decisions stall.</span> <span class='qd'><b>Risk functions reporting solely to the IT help desk</b>: the help desk is an operational support function, not an appropriate governance reporting point.</span> <span class='qd'><b>Structures that change every quarter to stay agile</b>: constant restructuring undermines the continuity and clarity governance depends on.</span>"},
{"id":"D1-004","domain":1,"obj":"1A3","diff":"easy","q":"In a RACI model for IT risk management, who is typically \"accountable\" for a specific risk being managed within tolerance?","options":["The internal audit function","The risk practitioner performing the assessment","The external regulator","The designated risk owner"],"answer":3,"explain":"<strong>The designated risk owner</strong> — the risk owner holds accountability for ensuring a specific risk is monitored and kept within acceptable levels, even when specific tasks are delegated to others.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The internal audit function</b>: audit provides independent assurance over how risk is managed but does not itself own accountability for the risk.</span> <span class='qd'><b>The risk practitioner performing the assessment</b>: the practitioner facilitates identification and analysis but is not the accountable owner of the risk.</span> <span class='qd'><b>The external regulator</b>: regulators set requirements and oversee compliance externally; they hold no internal accountability for the organization's risk.</span>"},
{"id":"D1-005","domain":1,"obj":"1A4","diff":"med","q":"An organization's risk culture is described as one where staff routinely hide negative risk information from management. What is the GREATEST danger this poses to risk governance?","options":["Staff morale will decline slightly","Training costs will increase","Risk decisions will be made on incomplete or inaccurate information","Audit cycles will take longer to complete"],"answer":2,"explain":"<strong>Risk decisions will be made on incomplete or inaccurate information</strong> — when negative risk information is concealed, decision-makers lose visibility into real exposure, undermining the entire basis for sound governance and response.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Staff morale will decline slightly</b>: morale is a secondary concern compared to the fundamental integrity of risk information reaching decision-makers.</span> <span class='qd'><b>Training costs will increase</b>: this is a minor, indirect effect and not the core governance danger of a concealment culture.</span> <span class='qd'><b>Audit cycles will take longer to complete</b>: audit duration is an operational inconvenience, not the primary risk of hidden information.</span>"},
{"id":"D1-006","domain":1,"obj":"1A5","diff":"easy","q":"The PRIMARY purpose of an IT risk policy is to:","options":["Provide step-by-step technical configuration instructions","Replace the need for a risk register","Establish the organization's overall intent and direction for managing IT risk","Satisfy a single external audit request"],"answer":2,"explain":"<strong>Establish the organization's overall intent and direction for managing IT risk</strong> — a policy sets the high-level expectations and direction from which standards, procedures, and specific controls are subsequently derived.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Provide step-by-step technical configuration instructions</b>: detailed configuration steps belong in procedures or standards, not policy.</span> <span class='qd'><b>Replace the need for a risk register</b>: a policy and a risk register serve different, complementary purposes; one does not substitute for the other.</span> <span class='qd'><b>Satisfy a single external audit request</b>: a policy exists for ongoing governance, not merely to answer a one-time audit inquiry.</span>"},
{"id":"D1-007","domain":1,"obj":"1A6","diff":"med","q":"During a business impact analysis, a risk practitioner discovers that a critical process has no documented recovery time objective (RTO). What is the BEST course of action?","options":["Assign an arbitrary RTO of 24 hours to all undocumented processes","Exclude the process from the business continuity plan","Wait until the next audit cycle to address the gap","Work with the process owner to define an RTO based on business impact tolerance"],"answer":3,"explain":"<strong>Work with the process owner to define an RTO based on business impact tolerance</strong> — the process owner best understands the business impact of downtime, so collaborating with them ensures the RTO reflects actual tolerance for disruption.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Assign an arbitrary RTO of 24 hours to all undocumented processes</b>: an arbitrary value ignores the actual criticality and impact profile of the process.</span> <span class='qd'><b>Exclude the process from the business continuity plan</b>: excluding a critical process leaves a significant continuity gap rather than resolving it.</span> <span class='qd'><b>Wait until the next audit cycle to address the gap</b>: delaying action leaves the organization exposed to an unmanaged continuity risk in the meantime.</span>"},
{"id":"D1-008","domain":1,"obj":"1A7","diff":"easy","q":"Which of the following is the PRIMARY reason an organization maintains an IT asset inventory as part of risk governance?","options":["It is required solely for insurance purposes","It eliminates the need for periodic risk assessments","It reduces the total number of assets an organization owns","It enables risk to be identified and assessed against known assets and their value"],"answer":3,"explain":"<strong>It enables risk to be identified and assessed against known assets and their value</strong> — you cannot manage risk to assets you do not know exist; an accurate inventory is the foundation for identifying, valuing, and prioritizing risk treatment.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>It is required solely for insurance purposes</b>: insurance may use inventory data, but that is not the primary governance reason for maintaining it.</span> <span class='qd'><b>It eliminates the need for periodic risk assessments</b>: an inventory supports risk assessment; it does not remove the ongoing need to perform one.</span> <span class='qd'><b>It reduces the total number of assets an organization owns</b>: inventorying assets does not itself reduce asset count; it improves visibility.</span>"},
{"id":"D1-009","domain":1,"obj":"1B1","diff":"med","q":"Which of the following BEST demonstrates that enterprise risk management (ERM) and IT risk management are effectively integrated?","options":["IT risk is managed entirely independently of the enterprise risk function","IT risks are evaluated and reported using the same criteria and escalation paths as other enterprise risks","The IT department maintains its own separate risk appetite statement","IT risk reports are produced but never shared with the enterprise risk committee"],"answer":1,"explain":"<strong>IT risks are evaluated and reported using the same criteria and escalation paths as other enterprise risks</strong> — true integration means IT risk is assessed and escalated consistently with all other enterprise risk categories, giving leadership a unified view.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>IT risk is managed entirely independently of the enterprise risk function</b>: independence without coordination is the opposite of integration and creates blind spots.</span> <span class='qd'><b>The IT department maintains its own separate risk appetite statement</b>: a separate appetite statement risks conflicting with the enterprise-level appetite set by the board.</span> <span class='qd'><b>IT risk reports are produced but never shared with the enterprise risk committee</b>: reports that never reach enterprise governance forums cannot inform enterprise-level decisions.</span>"},
{"id":"D1-010","domain":1,"obj":"1B2","diff":"hard","q":"A risk practitioner finds that IT risk assessments consistently use different likelihood and impact scales than those used for enterprise-level operational and financial risk. What is the GREATEST concern this creates?","options":["IT staff will require additional training on the scales","Risk cannot be meaningfully aggregated or compared across the enterprise risk profile","The IT risk register will require more storage space","Risk assessments will take longer to complete"],"answer":1,"explain":"<strong>Risk cannot be meaningfully aggregated or compared across the enterprise risk profile</strong> — inconsistent scales prevent leadership from rolling up and comparing IT risk alongside other enterprise risks, undermining a unified, prioritized view of exposure.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>IT staff will require additional training on the scales</b>: training need is a minor operational consequence, not the core governance concern.</span> <span class='qd'><b>The IT risk register will require more storage space</b>: storage capacity is irrelevant to the substantive risk aggregation problem.</span> <span class='qd'><b>Risk assessments will take longer to complete</b>: time impact is a secondary inconvenience compared to the loss of enterprise-wide comparability.</span>"},
{"id":"D1-011","domain":1,"obj":"1B3","diff":"med","q":"In the three lines of defense model, which line is PRIMARILY responsible for owning and managing risk on a day-to-day basis?","options":["The second line (risk management and compliance functions)","The third line (internal audit)","External auditors","The first line (business and IT operations)"],"answer":3,"explain":"<strong>The first line (business and IT operations)</strong> — operational management owns the risks generated by its activities and is responsible for implementing and operating the controls that keep those risks within tolerance.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The second line (risk management and compliance functions)</b>: the second line sets frameworks, provides oversight, and challenges the first line, but does not own the day-to-day risk itself.</span> <span class='qd'><b>The third line (internal audit)</b>: internal audit provides independent assurance over the first and second lines; it does not own operational risk.</span> <span class='qd'><b>External auditors</b>: external auditors are outside all three lines and provide independent assurance to stakeholders, not operational risk ownership.</span>"},
{"id":"D1-012","domain":1,"obj":"1B4","diff":"easy","q":"Which of the following BEST describes an organization's \"risk profile\"?","options":["A list of every control implemented across the enterprise","The total insurance coverage purchased by the organization","A composite view of the risks the organization faces across its operations at a given point in time","A single risk rated as most severe"],"answer":2,"explain":"<strong>A composite view of the risks the organization faces across its operations at a given point in time</strong> — the risk profile aggregates identified risks, their ratings, and treatment status into a holistic snapshot used to inform governance decisions.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A list of every control implemented across the enterprise</b>: a control inventory is a related but distinct artifact from the aggregated risk view.</span> <span class='qd'><b>The total insurance coverage purchased by the organization</b>: insurance is one risk response mechanism, not the profile of risks itself.</span> <span class='qd'><b>A single risk rated as most severe</b>: the profile reflects the full population of risks, not just the highest-rated one.</span>"},
{"id":"D1-013","domain":1,"obj":"1B5","diff":"med","q":"Which of the following BEST distinguishes risk appetite from risk tolerance?","options":["Risk appetite applies only to IT; tolerance applies only to finance","Risk appetite is set by IT management; tolerance is set by external regulators","There is no meaningful difference between the two terms","Risk appetite is the broad amount of risk an organization is willing to accept; tolerance is the acceptable variation around specific objectives"],"answer":3,"explain":"<strong>Risk appetite is the broad amount of risk an organization is willing to accept; tolerance is the acceptable variation around specific objectives</strong> — appetite is the strategic, enterprise-wide boundary, while tolerance defines the acceptable deviation for a particular objective or metric within that appetite.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Risk appetite applies only to IT; tolerance applies only to finance</b>: both concepts apply across all risk domains, not to isolated departments.</span> <span class='qd'><b>Risk appetite is set by IT management; tolerance is set by external regulators</b>: appetite is set by the board/senior management, and tolerance is typically defined internally to operationalize that appetite, not by regulators.</span> <span class='qd'><b>There is no meaningful difference between the two terms</b>: the two terms are related but distinct concepts with different levels of granularity.</span>"},
{"id":"D1-014","domain":1,"obj":"1B6","diff":"easy","q":"Which of the following frameworks is MOST commonly referenced for enterprise risk management principles and components?","options":["ITIL","COSO ERM","PMBOK","TOGAF"],"answer":1,"explain":"<strong>COSO ERM</strong> — the COSO Enterprise Risk Management framework provides widely recognized principles and components for integrating risk management with strategy and performance across an enterprise.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>ITIL</b>: ITIL is a framework for IT service management, not enterprise risk management.</span> <span class='qd'><b>PMBOK</b>: PMBOK is a project management body of knowledge, focused on project delivery rather than enterprise risk.</span> <span class='qd'><b>TOGAF</b>: TOGAF is an enterprise architecture framework, not a risk management framework.</span>"},
{"id":"D1-015","domain":1,"obj":"1B7","diff":"med","q":"An organization operates in a jurisdiction that just enacted a new data breach notification law. What is the risk practitioner's BEST FIRST step?","options":["Immediately notify all customers of a hypothetical breach","Wait for a regulator inquiry before taking any action","Delegate the entire matter to marketing for public relations handling","Assess the gap between current incident response capability and the new legal requirement"],"answer":3,"explain":"<strong>Assess the gap between current incident response capability and the new legal requirement</strong> — understanding where current capability falls short of the new obligation is the necessary first step to prioritize remediation and manage compliance risk.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Immediately notify all customers of a hypothetical breach</b>: notifying customers absent an actual breach is unnecessary and could cause needless alarm.</span> <span class='qd'><b>Wait for a regulator inquiry before taking any action</b>: reactive waiting exposes the organization to noncompliance risk that proactive gap assessment would prevent.</span> <span class='qd'><b>Delegate the entire matter to marketing for public relations handling</b>: this bypasses the risk and compliance analysis needed before any communications response.</span>"},
{"id":"D1-016","domain":1,"obj":"1B8","diff":"med","q":"Which of the following BEST distinguishes governance from management in the context of IT risk?","options":["Governance and management are interchangeable terms for the same function","Governance is performed only by the IT department","Management sets enterprise risk appetite; governance implements controls","Governance evaluates, directs, and monitors; management plans, builds, and runs risk activities"],"answer":3,"explain":"<strong>Governance evaluates, directs, and monitors; management plans, builds, and runs risk activities</strong> — governance sets direction and oversight at the board/executive level, while management executes and operates activities that fulfill that direction.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Governance and management are interchangeable terms for the same function</b>: they are distinct functions operating at different levels of the organization.</span> <span class='qd'><b>Governance is performed only by the IT department</b>: governance is an enterprise-level, board-driven responsibility, not confined to IT.</span> <span class='qd'><b>Management sets enterprise risk appetite; governance implements controls</b>: this reverses the actual roles; appetite-setting is a governance function and control implementation is a management function.</span>"},
{"id":"D1-017","domain":1,"obj":"1A1","diff":"med","q":"When developing an IT risk strategy, which of the following should be identified FIRST?","options":["The specific risk management software to purchase","The vendor to be engaged for risk consulting","The current state of risk management capability versus the desired future state","The exact wording of the risk policy"],"answer":2,"explain":"<strong>The current state of risk management capability versus the desired future state</strong> — strategy development starts with a gap analysis between where the organization stands today and where it needs to be, which then shapes the roadmap.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The specific risk management software to purchase</b>: tool selection is a downstream implementation decision, not a starting point.</span> <span class='qd'><b>The vendor to be engaged for risk consulting</b>: vendor engagement follows from defined needs that have not yet been established.</span> <span class='qd'><b>The exact wording of the risk policy</b>: policy drafting occurs after strategic direction and gaps are identified.</span>"},
{"id":"D1-018","domain":1,"obj":"1A2","diff":"hard","q":"An enterprise consolidates multiple business unit risk functions under a single chief risk officer (CRO). Which governance benefit is MOST significant from this change?","options":["Elimination of all business unit risk budgets","Guaranteed avoidance of all future incidents","Reduced need for board-level risk oversight","Consistent application of risk appetite and reporting standards across the enterprise"],"answer":3,"explain":"<strong>Consistent application of risk appetite and reporting standards across the enterprise</strong> — centralizing under one accountable executive drives uniform practices and improves enterprise-wide visibility into aggregated risk exposure.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Elimination of all business unit risk budgets</b>: budgets may be reallocated but are not eliminated; risk activities still require funding at the unit level.</span> <span class='qd'><b>Guaranteed avoidance of all future incidents</b>: no organizational structure can guarantee that incidents will never occur.</span> <span class='qd'><b>Reduced need for board-level risk oversight</b>: consolidation actually strengthens the case for board oversight by providing a clearer aggregated picture, not reducing the need for it.</span>"},
{"id":"D1-019","domain":1,"obj":"1A3","diff":"easy","q":"Which of the following roles is typically \"responsible\" for performing day-to-day risk identification activities within a business unit, while the business unit head remains accountable?","options":["The external regulator","The board of directors","The risk practitioner or designated risk coordinator embedded in the unit","The chief executive officer"],"answer":2,"explain":"<strong>The risk practitioner or designated risk coordinator embedded in the unit</strong> — this role performs the operational work of identifying and documenting risk, while accountability for outcomes remains with the business unit head.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The external regulator</b>: regulators set and enforce external requirements; they do not perform internal day-to-day risk identification.</span> <span class='qd'><b>The board of directors</b>: the board provides oversight and accountability at the highest level, not hands-on operational risk identification.</span> <span class='qd'><b>The chief executive officer</b>: the CEO holds overall accountability but delegates the operational identification work to risk practitioners.</span>"},
{"id":"D1-020","domain":1,"obj":"1A4","diff":"med","q":"An organization's incentive structure rewards project managers solely for on-time delivery, with no consideration of risk management practices. What is the MOST likely consequence for risk culture?","options":["Project delivery times will become highly unpredictable","Risk registers will automatically update themselves","Employees will request additional risk training voluntarily","Project teams may bypass risk processes to meet deadlines, increasing unmanaged risk"],"answer":3,"explain":"<strong>Project teams may bypass risk processes to meet deadlines, increasing unmanaged risk</strong> — incentives that reward only speed, without balancing risk considerations, drive behavior that sidesteps risk management to hit dates, eroding the risk culture.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Project delivery times will become highly unpredictable</b>: the incentive as described would likely make delivery times more consistent, not less, since that is what is being rewarded.</span> <span class='qd'><b>Risk registers will automatically update themselves</b>: registers do not update automatically regardless of incentive structures; this is not a plausible outcome.</span> <span class='qd'><b>Employees will request additional risk training voluntarily</b>: an incentive structure ignoring risk is more likely to reduce, not increase, voluntary engagement with risk practices.</span>"},
{"id":"D1-021","domain":1,"obj":"1A5","diff":"hard","q":"An audit finds that the IT risk policy grants exceptions liberally without a formal approval or tracking process. What is the GREATEST risk this presents?","options":["Increased printing costs for policy documents","Unmanaged risk accumulates outside of visibility and oversight","Delayed employee onboarding timelines","Reduced need for periodic policy review"],"answer":1,"explain":"<strong>Unmanaged risk accumulates outside of visibility and oversight</strong> — uncontrolled exceptions undermine the policy's intent and allow risk exposure to grow unseen and unmanaged by governance structures.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Increased printing costs for policy documents</b>: this is a trivial administrative matter unrelated to the substantive governance risk.</span> <span class='qd'><b>Delayed employee onboarding timelines</b>: exception handling for policy has no direct bearing on onboarding schedules.</span> <span class='qd'><b>Reduced need for periodic policy review</b>: uncontrolled exceptions would actually increase, not reduce, the need for review and correction.</span>"},
{"id":"D1-022","domain":1,"obj":"1A6","diff":"easy","q":"Which of the following BEST describes the relationship between business continuity planning (BCP) and IT risk management?","options":["BCP is unrelated to risk management and is solely an IT function","BCP replaces the need for a disaster recovery plan","BCP is only relevant to financial services organizations","BCP addresses the risk of disruption to critical business processes, informed by risk assessment findings"],"answer":3,"explain":"<strong>BCP addresses the risk of disruption to critical business processes, informed by risk assessment findings</strong> — continuity planning is a direct risk response, built on understanding which processes are critical and what risks threaten their availability.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>BCP is unrelated to risk management and is solely an IT function</b>: BCP spans the whole business and is deeply tied to enterprise risk management, not confined to IT.</span> <span class='qd'><b>BCP replaces the need for a disaster recovery plan</b>: DR is typically a technical subset that supports BCP; one does not replace the other.</span> <span class='qd'><b>BCP is only relevant to financial services organizations</b>: continuity planning is relevant to organizations across all industries, not one sector.</span>"},
{"id":"D1-023","domain":1,"obj":"1A7","diff":"med","q":"An organization discovers that several critical systems are not recorded in the asset management system. What is the MOST significant risk governance impact of this gap?","options":["The organization will incur higher software licensing fees","Help desk ticket volume will increase","Risk assessments and control coverage may be incomplete for those unrecorded systems","Employee satisfaction survey scores will decline"],"answer":2,"explain":"<strong>Risk assessments and control coverage may be incomplete for those unrecorded systems</strong> — systems missing from inventory are likely to be excluded from risk assessments and control application, creating blind spots in the risk profile.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The organization will incur higher software licensing fees</b>: licensing cost is a possible side issue, not the primary governance concern.</span> <span class='qd'><b>Help desk ticket volume will increase</b>: this is unrelated to the core issue of unassessed risk exposure.</span> <span class='qd'><b>Employee satisfaction survey scores will decline</b>: asset inventory gaps have no direct bearing on employee satisfaction.</span>"},
{"id":"D1-024","domain":1,"obj":"1B1","diff":"easy","q":"Which of the following is the PRIMARY objective of enterprise risk management (ERM)?","options":["To eliminate all risk from the organization","To transfer all risk to insurance providers","To ensure every department has an identical risk appetite","To provide a structured approach for identifying, assessing, and responding to risk in support of enterprise objectives"],"answer":3,"explain":"<strong>To provide a structured approach for identifying, assessing, and responding to risk in support of enterprise objectives</strong> — ERM exists to systematically manage risk so the organization can pursue its objectives with an informed understanding of exposure.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>To eliminate all risk from the organization</b>: eliminating all risk is neither feasible nor desirable; ERM manages risk to an acceptable level, not zero.</span> <span class='qd'><b>To transfer all risk to insurance providers</b>: transfer is only one of several risk response options, not the sole objective of ERM.</span> <span class='qd'><b>To ensure every department has an identical risk appetite</b>: departments may have different tolerances within an overall enterprise appetite; uniformity is not the goal.</span>"},
{"id":"D1-025","domain":1,"obj":"1B2","diff":"med","q":"Which of the following BEST supports alignment between IT risk management and enterprise risk management?","options":["Allowing IT to define its own unique risk categories without enterprise input","Reporting IT risk only to the chief information officer","Excluding IT risk from the enterprise risk register entirely","Using a common risk taxonomy and consistent escalation thresholds across both functions"],"answer":3,"explain":"<strong>Using a common risk taxonomy and consistent escalation thresholds across both functions</strong> — shared language and thresholds ensure IT risk can be understood, compared, and escalated consistently within the broader enterprise risk management process.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Allowing IT to define its own unique risk categories without enterprise input</b>: unique, uncoordinated categories prevent meaningful comparison with other enterprise risks.</span> <span class='qd'><b>Reporting IT risk only to the chief information officer</b>: limiting reporting to one executive bypasses the broader enterprise risk governance structure.</span> <span class='qd'><b>Excluding IT risk from the enterprise risk register entirely</b>: exclusion is the opposite of alignment and leaves a significant gap in the enterprise risk profile.</span>"},
{"id":"D1-026","domain":1,"obj":"1B3","diff":"easy","q":"Which of the following BEST describes the role of the second line of defense in IT risk management?","options":["Executing daily IT operations and applying controls","Establishing risk frameworks, policies, and providing oversight and challenge to the first line","Providing independent assurance to the audit committee","Owning and accepting residual risk on behalf of the enterprise"],"answer":1,"explain":"<strong>Establishing risk frameworks, policies, and providing oversight and challenge to the first line</strong> — the second line, typically risk management and compliance, sets the framework and monitors/challenges how the first line manages risk.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Executing daily IT operations and applying controls</b>: this describes the first line, which owns and operates the risk-generating activities.</span> <span class='qd'><b>Providing independent assurance to the audit committee</b>: this is the role of the third line, internal audit, not the second line.</span> <span class='qd'><b>Owning and accepting residual risk on behalf of the enterprise</b>: risk ownership and acceptance rests with business/risk owners and senior management, not the second-line function itself.</span>"},
{"id":"D1-027","domain":1,"obj":"1B4","diff":"med","q":"A newly appointed risk practitioner wants to understand the organization's overall risk profile. Which source would be MOST useful as a starting point?","options":["A single business unit's incident log from last month","The enterprise risk register aggregating identified risks across business units","The organization's marketing plan","An individual employee's performance review"],"answer":1,"explain":"<strong>The enterprise risk register aggregating identified risks across business units</strong> — a consolidated risk register provides the broadest, most structured view of the organization's current risk exposure, making it the ideal starting point.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A single business unit's incident log from last month</b>: this is a narrow, time-bound slice that does not represent the enterprise-wide profile.</span> <span class='qd'><b>The organization's marketing plan</b>: a marketing plan addresses commercial strategy, not risk exposure.</span> <span class='qd'><b>An individual employee's performance review</b>: this is unrelated to organizational risk and offers no insight into the risk profile.</span>"},
{"id":"D1-028","domain":1,"obj":"1B5","diff":"hard","q":"A business unit consistently launches new digital products that exceed the enterprise's approved risk tolerance for data privacy, though each individual launch remains under the board-approved risk appetite ceiling. What should the risk practitioner do FIRST?","options":["Allow the pattern to continue since overall appetite has not been exceeded","Escalate the pattern of tolerance breaches for governance review, since repeated breaches signal a systemic control gap","Instruct the business unit to stop launching new products permanently","Remove data privacy from the risk taxonomy since it is causing repeated issues"],"answer":1,"explain":"<strong>Escalate the pattern of tolerance breaches for governance review, since repeated breaches signal a systemic control gap</strong> — repeated tolerance breaches, even within overall appetite, indicate a recurring control weakness that governance needs visibility into and must address.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Allow the pattern to continue since overall appetite has not been exceeded</b>: tolerance breaches are meaningful signals in their own right and should not be dismissed just because aggregate appetite is not breached.</span> <span class='qd'><b>Instruct the business unit to stop launching new products permanently</b>: halting all launches is a disproportionate response instead of addressing the underlying control gap.</span> <span class='qd'><b>Remove data privacy from the risk taxonomy since it is causing repeated issues</b>: removing a risk category to avoid uncomfortable findings ignores the real, recurring exposure rather than managing it.</span>"},
{"id":"D1-029","domain":1,"obj":"1B6","diff":"med","q":"An organization wants to adopt a risk governance framework that emphasizes evaluating, directing, and monitoring IT-related enterprise goals. Which framework BEST fits this need?","options":["PMBOK","COBIT","Six Sigma","Agile Scrum"],"answer":1,"explain":"<strong>COBIT</strong> — COBIT is specifically structured around governance objectives (evaluate, direct, monitor) and management objectives, making it well suited to IT-related enterprise governance needs.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>PMBOK</b>: PMBOK is a project management framework, not an IT governance framework.</span> <span class='qd'><b>Six Sigma</b>: Six Sigma is a process improvement methodology focused on quality and variation reduction, not governance.</span> <span class='qd'><b>Agile Scrum</b>: Scrum is a software delivery framework, not a governance or risk framework.</span>"},
{"id":"D1-030","domain":1,"obj":"1B7","diff":"easy","q":"Which of the following is the MOST important reason to maintain a register of legal and regulatory requirements relevant to IT operations?","options":["To reduce the number of vendors under contract","To ensure risk assessments account for applicable compliance obligations","To eliminate the need for a privacy policy","To simplify the organizational chart"],"answer":1,"explain":"<strong>To ensure risk assessments account for applicable compliance obligations</strong> — a current register of legal and regulatory requirements ensures risk identification and treatment properly reflect obligations the organization must meet.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>To reduce the number of vendors under contract</b>: vendor count is unrelated to tracking legal and regulatory obligations.</span> <span class='qd'><b>To eliminate the need for a privacy policy</b>: a requirements register supports policy development; it does not eliminate the need for a privacy policy.</span> <span class='qd'><b>To simplify the organizational chart</b>: organizational structure is a separate matter from legal and regulatory tracking.</span>"},
{"id":"D1-031","domain":1,"obj":"1B8","diff":"hard","q":"A board of directors delegates all IT risk oversight to the CIO with no further board involvement or reporting. What is the GREATEST governance concern with this arrangement?","options":["The CIO will lack the technical skill to manage IT risk","The board retains ultimate accountability for risk but loses visibility needed to fulfill that accountability","IT costs will increase substantially","The organization will fail its next financial audit"],"answer":1,"explain":"<strong>The board retains ultimate accountability for risk but loses visibility needed to fulfill that accountability</strong> — delegation of execution is appropriate, but the board cannot delegate away its ultimate accountability, and having no reporting mechanism leaves it unable to exercise effective oversight.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The CIO will lack the technical skill to manage IT risk</b>: the scenario does not indicate a skills gap; the concern is about governance oversight, not competence.</span> <span class='qd'><b>IT costs will increase substantially</b>: cost impact is speculative and not the core governance issue described.</span> <span class='qd'><b>The organization will fail its next financial audit</b>: this is an unsupported leap; the described gap is about risk oversight, not financial audit outcomes specifically.</span>"},
{"id":"D1-032","domain":1,"obj":"1A1","diff":"med","q":"An organization's IT risk strategy references only compliance with a single regulatory framework and ignores other business risk drivers. What is the MOST significant weakness of this strategy?","options":["It will make the organization immune to regulatory fines","It may leave significant non-compliance-related business risks unaddressed","It requires no periodic review going forward","It automatically improves the organization's credit rating"],"answer":1,"explain":"<strong>It may leave significant non-compliance-related business risks unaddressed</strong> — a strategy narrowly focused on one regulatory framework overlooks operational, strategic, and other business risks that fall outside that framework's scope.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>It will make the organization immune to regulatory fines</b>: compliance with one framework does not guarantee immunity from fines under other applicable laws or rules.</span> <span class='qd'><b>It requires no periodic review going forward</b>: all strategies require ongoing review regardless of scope; a narrow focus does not remove this need.</span> <span class='qd'><b>It automatically improves the organization's credit rating</b>: credit ratings depend on many financial factors unrelated to the scope of an IT risk strategy.</span>"},
{"id":"D1-033","domain":1,"obj":"1A2","diff":"easy","q":"Which of the following BEST supports clear accountability in an organization's IT risk governance structure?","options":["Verbal agreements made during informal hallway conversations","Explicitly assigned risk ownership documented and communicated across the enterprise","Rotating ownership of every risk on a monthly basis","Leaving ownership undefined so any manager can respond as needed"],"answer":1,"explain":"<strong>Explicitly assigned risk ownership documented and communicated across the enterprise</strong> — formal, documented, and communicated ownership removes ambiguity about who is accountable for managing a given risk.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Verbal agreements made during informal hallway conversations</b>: informal, undocumented arrangements are unreliable and cannot be consistently enforced or audited.</span> <span class='qd'><b>Rotating ownership of every risk on a monthly basis</b>: frequent rotation undermines continuity and depth of understanding needed for effective risk ownership.</span> <span class='qd'><b>Leaving ownership undefined so any manager can respond as needed</b>: undefined ownership creates gaps where risks may go unmanaged because no one is clearly responsible.</span>"},
{"id":"D1-034","domain":1,"obj":"1A3","diff":"med","q":"A risk practitioner is building a RACI chart for a new third-party risk assessment process. Which consideration is MOST important when assigning the \"consulted\" role?","options":["Ensuring as many people as possible are listed to cover all bases","Identifying stakeholders whose expertise should inform the decision before it is finalized","Assigning the role only to external auditors","Limiting consultation to the risk practitioner alone"],"answer":1,"explain":"<strong>Identifying stakeholders whose expertise should inform the decision before it is finalized</strong> — the \"consulted\" role should include those whose input is genuinely needed to make an informed decision, ensuring relevant expertise is captured without diluting accountability.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Ensuring as many people as possible are listed to cover all bases</b>: over-listing consulted parties slows decision-making and dilutes meaningful input.</span> <span class='qd'><b>Assigning the role only to external auditors</b>: external auditors are not the sole source of relevant expertise for an internal risk process.</span> <span class='qd'><b>Limiting consultation to the risk practitioner alone</b>: this defeats the purpose of the consulted role, which is to gather outside input, not rely on a single person.</span>"},
{"id":"D1-035","domain":1,"obj":"1A4","diff":"easy","q":"Which of the following is the STRONGEST indicator of a positive risk culture within an organization?","options":["Risk incidents are never discussed openly","Employees proactively report risk issues without fear of retribution","Only senior management is permitted to discuss risk topics","Risk reporting is discouraged to avoid negative publicity"],"answer":1,"explain":"<strong>Employees proactively report risk issues without fear of retribution</strong> — a healthy risk culture is characterized by openness and psychological safety, encouraging timely reporting so issues can be addressed before they escalate.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Risk incidents are never discussed openly</b>: silence around incidents is a sign of a poor, not positive, risk culture.</span> <span class='qd'><b>Only senior management is permitted to discuss risk topics</b>: restricting risk discussion to senior management stifles the broad engagement a healthy culture requires.</span> <span class='qd'><b>Risk reporting is discouraged to avoid negative publicity</b>: discouraging reporting actively undermines transparency and is a hallmark of a weak risk culture.</span>"},
{"id":"D1-036","domain":1,"obj":"1A5","diff":"med","q":"An organization has numerous IT standards but no overarching risk policy tying them together. What is the MOST significant governance gap this creates?","options":["Standards will automatically become outdated within a year","Standards may lack a consistent, unifying statement of risk intent and direction from leadership","The organization cannot use any technical controls","Employees will be unable to access the standards documents"],"answer":1,"explain":"<strong>Standards may lack a consistent, unifying statement of risk intent and direction from leadership</strong> — without an overarching policy, individual standards can drift out of alignment with each other and with leadership's overall risk direction.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Standards will automatically become outdated within a year</b>: the absence of a policy does not by itself cause standards to expire on a fixed timeline.</span> <span class='qd'><b>The organization cannot use any technical controls</b>: technical controls can still be implemented even without an overarching policy; the concern is consistency and direction, not capability.</span> <span class='qd'><b>Employees will be unable to access the standards documents</b>: document accessibility is unrelated to whether a unifying policy exists.</span>"},
{"id":"D1-037","domain":1,"obj":"1A6","diff":"hard","q":"During disaster recovery testing, a risk practitioner finds that the recovery point objective (RPO) achieved is significantly worse than what business stakeholders believe is in place. What is the BEST course of action?","options":["Update the documentation to reflect the tested RPO without further discussion","Report the gap to stakeholders and reassess whether current backup and replication capability can meet business needs","Cancel all future disaster recovery testing to avoid further discrepancies","Assume the test was flawed and disregard the results"],"answer":1,"explain":"<strong>Report the gap to stakeholders and reassess whether current backup and replication capability can meet business needs</strong> — surfacing the actual gap allows the organization to decide whether to invest in improved capability or adjust expectations, closing the disconnect between perceived and actual resilience.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Update the documentation to reflect the tested RPO without further discussion</b>: silently updating documentation without engaging stakeholders leaves the underlying business risk unaddressed.</span> <span class='qd'><b>Cancel all future disaster recovery testing to avoid further discrepancies</b>: eliminating testing removes the very mechanism needed to detect and correct such gaps.</span> <span class='qd'><b>Assume the test was flawed and disregard the results</b>: dismissing results without justification risks ignoring a real capability gap.</span>"},
{"id":"D1-038","domain":1,"obj":"1A7","diff":"med","q":"Which of the following BEST supports effective ongoing management of IT asset-related risk?","options":["Conducting an asset inventory once at system go-live and never revisiting it","Regularly reconciling the asset inventory against actual deployed systems and updating risk assessments accordingly","Relying exclusively on end users to self-report their own devices","Removing assets from the inventory once they are no longer under warranty"],"answer":1,"explain":"<strong>Regularly reconciling the asset inventory against actual deployed systems and updating risk assessments accordingly</strong> — ongoing reconciliation ensures the inventory (and therefore risk assessment) stays accurate as the environment changes over time.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Conducting an asset inventory once at system go-live and never revisiting it</b>: a one-time inventory quickly becomes stale as assets are added, retired, or changed.</span> <span class='qd'><b>Relying exclusively on end users to self-report their own devices</b>: self-reporting alone is unreliable and likely to miss unauthorized or forgotten assets.</span> <span class='qd'><b>Removing assets from the inventory once they are no longer under warranty</b>: warranty status is unrelated to whether an asset is still in use and carries risk.</span>"},
{"id":"D1-039","domain":1,"obj":"1B1","diff":"hard","q":"Senior management wants to know whether the organization's aggregate risk exposure is trending favorably. Which approach BEST supports this need?","options":["Reviewing a single department's risk register for the current month only","Counting the total number of controls implemented to date","Trending the enterprise risk register's key risk indicators and residual risk ratings over multiple reporting periods","Reviewing the most recent penetration test report in isolation"],"answer":2,"explain":"<strong>Trending the enterprise risk register's key risk indicators and residual risk ratings over multiple reporting periods</strong> — tracking KRIs and residual risk over time across the enterprise gives leadership a meaningful, longitudinal view of whether exposure is improving or worsening.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Reviewing a single department's risk register for the current month only</b>: a single department and single period cannot represent enterprise-wide trending.</span> <span class='qd'><b>Counting the total number of controls implemented to date</b>: control counts do not measure whether risk exposure is actually decreasing.</span> <span class='qd'><b>Reviewing the most recent penetration test report in isolation</b>: a single technical test is a narrow, point-in-time input, not a trend indicator of aggregate exposure.</span>"},
{"id":"D1-040","domain":1,"obj":"1B2","diff":"easy","q":"Which of the following BEST illustrates IT risk being treated as a subset of enterprise risk rather than a standalone concern?","options":["IT risk is tracked only in a spreadsheet maintained by the network team","IT risk decisions are made without reference to enterprise risk appetite","IT risk scenarios are incorporated into the enterprise risk assessment alongside financial and operational risk","The IT department is excluded from enterprise risk workshops"],"answer":2,"explain":"<strong>IT risk scenarios are incorporated into the enterprise risk assessment alongside financial and operational risk</strong> — including IT risk within the broader enterprise risk assessment reflects that IT risk is one category within the overall enterprise risk landscape, not a separate silo.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>IT risk is tracked only in a spreadsheet maintained by the network team</b>: an isolated, informally maintained tracker reflects siloed practice, not integration with enterprise risk.</span> <span class='qd'><b>IT risk decisions are made without reference to enterprise risk appetite</b>: ignoring enterprise risk appetite is the opposite of alignment.</span> <span class='qd'><b>The IT department is excluded from enterprise risk workshops</b>: exclusion from these workshops indicates disconnection, not integration.</span>"},
{"id":"D1-041","domain":1,"obj":"1B3","diff":"med","q":"An internal audit function begins performing day-to-day control testing and remediation activities for the business units it audits. What is the GREATEST concern with this arrangement?","options":["It will reduce the audit department's headcount requirements","It eliminates the need for a first-line control environment","It compromises the independence internal audit needs to provide objective assurance","It guarantees findings will always be favorable to management"],"answer":2,"explain":"<strong>It compromises the independence internal audit needs to provide objective assurance</strong> — when the third line takes on first-line operational duties, it can no longer independently assess those same activities, undermining the integrity of the three lines model.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>It will reduce the audit department's headcount requirements</b>: taking on more operational work would likely increase, not reduce, workload and headcount needs.</span> <span class='qd'><b>It eliminates the need for a first-line control environment</b>: the first line's ownership of controls is still needed regardless of what audit does; this arrangement does not eliminate that need.</span> <span class='qd'><b>It guarantees findings will always be favorable to management</b>: there is no guarantee of favorable findings; the real issue is loss of independence, not bias toward positive outcomes.</span>"},
{"id":"D1-042","domain":1,"obj":"1B4","diff":"med","q":"Which of the following changes to an organization's risk profile would MOST warrant immediate escalation to senior management?","options":["A minor decrease in a low-priority risk's likelihood rating","The addition of a new low-risk vendor to the vendor list","A newly identified risk that, if realized, would exceed the board-approved risk appetite","A scheduled, routine update to the risk register format"],"answer":2,"explain":"<strong>A newly identified risk that, if realized, would exceed the board-approved risk appetite</strong> — a risk with potential impact beyond the approved appetite represents a material change in exposure that senior management must be made aware of promptly.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A minor decrease in a low-priority risk's likelihood rating</b>: a small favorable change to a low-priority risk does not warrant urgent escalation.</span> <span class='qd'><b>The addition of a new low-risk vendor to the vendor list</b>: a low-risk addition does not represent a material shift in the risk profile requiring immediate escalation.</span> <span class='qd'><b>A scheduled, routine update to the risk register format</b>: a formatting update is an administrative change, not a substantive risk event.</span>"},
{"id":"D1-043","domain":1,"obj":"1B5","diff":"easy","q":"Who is typically responsible for formally approving the enterprise's overall risk appetite statement?","options":["The systems administrator","The help desk manager","The board of directors or equivalent senior governing body","The marketing coordinator"],"answer":2,"explain":"<strong>The board of directors or equivalent senior governing body</strong> — setting the enterprise-level boundary of acceptable risk is a top governance decision that belongs to the board or an equivalent senior governing body.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The systems administrator</b>: this is a technical operational role with no authority over enterprise risk appetite.</span> <span class='qd'><b>The help desk manager</b>: help desk management has no governance role in setting enterprise-level risk boundaries.</span> <span class='qd'><b>The marketing coordinator</b>: this role has no involvement in enterprise governance decisions regarding risk appetite.</span>"},
{"id":"D1-044","domain":1,"obj":"1B6","diff":"med","q":"An organization wants a risk management framework specifically structured around principles, framework, and process to integrate risk management into all organizational activities. Which framework BEST matches this description?","options":["ITIL v4","CMMI","ISO 31000","Scrum"],"answer":2,"explain":"<strong>ISO 31000</strong> — ISO 31000 is explicitly organized around principles, a framework, and a process for integrating risk management throughout an organization's governance and operations.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>ITIL v4</b>: ITIL v4 is focused on IT service management practices, not a dedicated risk management structure.</span> <span class='qd'><b>CMMI</b>: CMMI is a process/capability maturity model, primarily for software and process improvement, not a risk framework.</span> <span class='qd'><b>Scrum</b>: Scrum is an agile software delivery framework unrelated to enterprise risk management structure.</span>"},
{"id":"D1-045","domain":1,"obj":"1B7","diff":"hard","q":"A multinational organization discovers that a proposed IT outsourcing arrangement would violate data residency requirements in one of the countries where it operates. What is the BEST course of action for the risk practitioner?","options":["Proceed with the arrangement since it benefits the majority of the organization's operations","Only address the issue if a regulator raises it during an audit","Work with legal and the business to redesign the arrangement so it complies with data residency requirements before proceeding","Move the affected country's operations under a different subsidiary to bypass the requirement"],"answer":2,"explain":"<strong>Work with legal and the business to redesign the arrangement so it complies with data residency requirements before proceeding</strong> — proactively resolving the compliance conflict before implementation avoids legal exposure and reflects sound risk governance over contractual and regulatory obligations.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Proceed with the arrangement since it benefits the majority of the organization's operations</b>: proceeding despite a known legal violation exposes the organization to significant regulatory and legal risk.</span> <span class='qd'><b>Only address the issue if a regulator raises it during an audit</b>: waiting for a regulator to catch a known violation is a reactive, high-risk approach rather than proactive governance.</span> <span class='qd'><b>Move the affected country's operations under a different subsidiary to bypass the requirement</b>: restructuring to circumvent a legal requirement does not resolve the underlying compliance risk and may itself be improper.</span>"},
{"id":"D1-046","domain":1,"obj":"1B8","diff":"easy","q":"Which of the following activities is MOST clearly a governance function rather than a management function?","options":["Configuring firewall rules on a production server","Running a daily vulnerability scan","The board approving the enterprise's overall risk appetite statement","Updating a ticketing system for incident tracking"],"answer":2,"explain":"<strong>The board approving the enterprise's overall risk appetite statement</strong> — approving the enterprise-wide boundary for acceptable risk is a direction-setting, oversight activity that sits squarely within governance.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Configuring firewall rules on a production server</b>: this is a hands-on technical task performed by management/operations, not a governance activity.</span> <span class='qd'><b>Running a daily vulnerability scan</b>: this is an operational, recurring management task, not a governance decision.</span> <span class='qd'><b>Updating a ticketing system for incident tracking</b>: this is administrative operational work, unrelated to governance-level direction-setting.</span>"},
{"id":"D1-047","domain":1,"obj":"1A1","diff":"hard","q":"A risk practitioner is asked to validate whether the organization's IT risk strategy remains fit for purpose after a major merger. Which factor is MOST important to reassess FIRST?","options":["Whether the merged organization's office locations need repainting","Whether the original strategy document uses the correct font","Whether the combined entity's business objectives and risk appetite have changed as a result of the merger","Whether the original IT risk strategy was ever printed and filed"],"answer":2,"explain":"<strong>Whether the combined entity's business objectives and risk appetite have changed as a result of the merger</strong> — a merger often fundamentally shifts business objectives and the combined entity's risk appetite, so the strategy must be reassessed against this new context first.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Whether the merged organization's office locations need repainting</b>: this is a facilities matter entirely unrelated to risk strategy validity.</span> <span class='qd'><b>Whether the original strategy document uses the correct font</b>: formatting details are irrelevant to whether the substance of the strategy remains valid.</span> <span class='qd'><b>Whether the original IT risk strategy was ever printed and filed</b>: physical filing status has no bearing on the strategy's continued relevance.</span>"},
{"id":"D1-048","domain":1,"obj":"1A2","diff":"med","q":"Which organizational characteristic would MOST likely undermine effective IT risk governance?","options":["A single, clearly designated risk owner for each major risk category","Documented escalation paths from operational teams to senior management","Overlapping and unclear accountability for risk decisions between multiple committees","Periodic reporting of key risk indicators to the board"],"answer":2,"explain":"<strong>Overlapping and unclear accountability for risk decisions between multiple committees</strong> — ambiguous, overlapping authority creates confusion about who is responsible for decisions, causing delays and gaps in effective risk management.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A single, clearly designated risk owner for each major risk category</b>: clear ownership is a governance strength, not a weakness.</span> <span class='qd'><b>Documented escalation paths from operational teams to senior management</b>: documented escalation paths support, rather than undermine, effective governance.</span> <span class='qd'><b>Periodic reporting of key risk indicators to the board</b>: regular KRI reporting strengthens board oversight and is a governance benefit.</span>"},
{"id":"D1-049","domain":1,"obj":"1A3","diff":"med","q":"A risk practitioner notices that two departments both believe the other is accountable for managing a specific third-party risk. What is the BEST way to resolve this?","options":["Let each department continue operating under its own assumption","Assign accountability to whichever department complains loudest","Formally clarify and document accountability through an updated RACI assignment approved by management","Remove the risk from the register since ownership cannot be determined"],"answer":2,"explain":"<strong>Formally clarify and document accountability through an updated RACI assignment approved by management</strong> — resolving ambiguous accountability requires a clear, management-endorsed assignment so there is no future confusion about ownership.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Let each department continue operating under its own assumption</b>: leaving the ambiguity unresolved risks the risk being unmanaged by either party.</span> <span class='qd'><b>Assign accountability to whichever department complains loudest</b>: this is an arbitrary approach that does not reflect a sound governance rationale.</span> <span class='qd'><b>Remove the risk from the register since ownership cannot be determined</b>: removing a real risk from the register because ownership is unclear ignores the risk rather than resolving the accountability gap.</span>"},
{"id":"D1-050","domain":1,"obj":"1A4","diff":"hard","q":"Executives publicly emphasize the importance of risk management, but consistently approve projects that bypass the risk assessment process to meet deadlines. What is the MOST significant impact on organizational risk culture?","options":["Employees will believe risk assessments are mandatory in all cases","A gap between stated values and actual behavior will erode trust in the risk program and encourage further bypassing","The organization's risk appetite statement will automatically update","Project success rates will improve as a direct result"],"answer":1,"explain":"<strong>A gap between stated values and actual behavior will erode trust in the risk program and encourage further bypassing</strong> — when leadership's actions contradict their stated commitment to risk management, it signals that the process is optional, undermining the credibility of governance and normalizing further circumvention.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Employees will believe risk assessments are mandatory in all cases</b>: the described behavior actually teaches employees the opposite — that assessments can be skipped under pressure.</span> <span class='qd'><b>The organization's risk appetite statement will automatically update</b>: risk appetite statements do not change automatically based on behavior; they require deliberate governance action.</span> <span class='qd'><b>Project success rates will improve as a direct result</b>: bypassing risk assessment is more likely to increase the chance of unmanaged issues, not improve success rates.</span>"},
{"id":"D1-051","domain":1,"obj":"1A5","diff":"easy","q":"Which of the following is the BEST way to ensure IT risk policies remain relevant over time?","options":["Publish the policy once and never revisit it","Allow each department to rewrite the policy independently","Establish a periodic review cycle tied to business, regulatory, and threat landscape changes","Require board approval only for the initial policy draft"],"answer":2,"explain":"<strong>Establish a periodic review cycle tied to business, regulatory, and threat landscape changes</strong> — a structured review cadence ensures the policy adapts as the organization, its obligations, and its risk environment evolve.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Publish the policy once and never revisit it</b>: a static policy quickly becomes outdated as conditions change.</span> <span class='qd'><b>Allow each department to rewrite the policy independently</b>: decentralized rewriting undermines the consistency an enterprise policy is meant to provide.</span> <span class='qd'><b>Require board approval only for the initial policy draft</b>: ongoing changes also need appropriate governance approval to remain valid and enforceable.</span>"},
{"id":"D1-052","domain":1,"obj":"1A6","diff":"med","q":"A risk practitioner is prioritizing which business processes to include first in the business continuity plan. Which factor should carry the MOST weight?","options":["Employee preference for which processes to protect","The business impact of process disruption as determined by the business impact analysis","The age of the technology supporting the process","The number of employees assigned to the process"],"answer":1,"explain":"<strong>The business impact of process disruption as determined by the business impact analysis</strong> — prioritization should be driven by the actual consequences of disruption to the business, which the BIA is specifically designed to quantify.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Employee preference for which processes to protect</b>: personal preference is subjective and not a reliable basis for prioritizing continuity investment.</span> <span class='qd'><b>The age of the technology supporting the process</b>: technology age alone does not indicate business criticality.</span> <span class='qd'><b>The number of employees assigned to the process</b>: headcount does not necessarily correlate with the business impact of an outage.</span>"},
{"id":"D1-053","domain":1,"obj":"1A7","diff":"hard","q":"An organization's cloud usage has grown significantly through business units independently provisioning services without informing IT or risk management. What is the GREATEST risk this shadow IT practice creates?","options":["Increased employee satisfaction with faster provisioning","Risks associated with unmanaged assets going unidentified and unassessed","Reduced cloud service costs across the enterprise","Simplified vendor management processes"],"answer":1,"explain":"<strong>Risks associated with unmanaged assets going unidentified and unassessed</strong> — assets provisioned outside formal processes are unlikely to appear in the asset inventory or undergo risk assessment, creating significant blind spots in the risk profile.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Increased employee satisfaction with faster provisioning</b>: while this could be a side effect, it is not the governance risk of concern here.</span> <span class='qd'><b>Reduced cloud service costs across the enterprise</b>: uncoordinated provisioning more commonly leads to duplicated spend and higher costs, not savings.</span> <span class='qd'><b>Simplified vendor management processes</b>: shadow IT actually complicates vendor management by creating untracked relationships.</span>"},
{"id":"D1-054","domain":1,"obj":"1B1","diff":"easy","q":"Which of the following BEST describes the relationship between IT risk management and enterprise risk management (ERM)?","options":["IT risk management operates independently and does not need to report to ERM","IT risk is one category of risk that should be integrated into the broader ERM program","ERM only addresses financial risk, while IT risk is handled separately","IT risk management replaces the need for ERM"],"answer":1,"explain":"<strong>IT risk is one category of risk that should be integrated into the broader ERM program</strong> — IT risk is a component of the overall enterprise risk landscape and should be managed and reported within the ERM structure alongside other risk categories.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>IT risk management operates independently and does not need to report to ERM</b>: operating in isolation from ERM creates gaps in enterprise-wide risk visibility.</span> <span class='qd'><b>ERM only addresses financial risk, while IT risk is handled separately</b>: ERM is meant to span all risk categories, including IT, not just financial risk.</span> <span class='qd'><b>IT risk management replaces the need for ERM</b>: IT risk management is a subset of, not a replacement for, enterprise-wide risk management.</span>"},
{"id":"D1-055","domain":1,"obj":"1B2","diff":"med","q":"A risk practitioner is asked to help the enterprise risk committee understand which IT risks pose the greatest threat to strategic objectives. Which approach is MOST effective?","options":["Present a raw list of every technical vulnerability discovered in the past year","Map significant IT risks to the specific strategic objectives they threaten, with business impact and likelihood","Present only the total dollar amount spent on IT security tools","Provide a list of all IT staff certifications held"],"answer":1,"explain":"<strong>Map significant IT risks to the specific strategic objectives they threaten, with business impact and likelihood</strong> — connecting risks directly to strategic objectives, along with impact and likelihood, gives the committee the context needed to prioritize and act.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Present a raw list of every technical vulnerability discovered in the past year</b>: an unfiltered technical list overwhelms the committee without connecting to business impact.</span> <span class='qd'><b>Present only the total dollar amount spent on IT security tools</b>: spending figures alone do not communicate which risks threaten strategic objectives.</span> <span class='qd'><b>Provide a list of all IT staff certifications held</b>: staff credentials are unrelated to identifying which risks threaten strategy.</span>"},
{"id":"D1-056","domain":1,"obj":"1B3","diff":"easy","q":"Which of the following BEST describes the primary function of the third line of defense?","options":["Owning and operating day-to-day controls","Setting enterprise risk policy and frameworks","Providing independent, objective assurance over the effectiveness of governance, risk management, and controls","Approving the annual IT budget"],"answer":2,"explain":"<strong>Providing independent, objective assurance over the effectiveness of governance, risk management, and controls</strong> — the third line, internal audit, exists specifically to independently evaluate how well the first and second lines are managing risk and controls.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Owning and operating day-to-day controls</b>: this describes the first line's operational responsibility, not the third line's assurance role.</span> <span class='qd'><b>Setting enterprise risk policy and frameworks</b>: this is typically a second-line responsibility, establishing frameworks the first line follows.</span> <span class='qd'><b>Approving the annual IT budget</b>: budget approval is a management or governance financial decision, not an audit assurance function.</span>"},
{"id":"D1-057","domain":1,"obj":"1B4","diff":"med","q":"An organization's risk profile shows a large concentration of high risks in a single business unit while other units show few risks. What should the risk practitioner consider FIRST?","options":["Immediately shutting down the high-risk business unit","Ignoring the discrepancy since risk profiles naturally vary","Whether the concentration reflects genuine risk exposure or inconsistent assessment practices across units","Reassigning all staff from the high-risk unit to other units"],"answer":2,"explain":"<strong>Whether the concentration reflects genuine risk exposure or inconsistent assessment practices across units</strong> — before acting on the data, it is important to verify the concentration is real and not an artifact of uneven assessment rigor or reporting practices between units.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Immediately shutting down the high-risk business unit</b>: this drastic action is premature before understanding whether the data itself is reliable.</span> <span class='qd'><b>Ignoring the discrepancy since risk profiles naturally vary</b>: dismissing a significant concentration without investigation risks missing either a real problem or a data quality issue.</span> <span class='qd'><b>Reassigning all staff from the high-risk unit to other units</b>: staff reassignment does not address the underlying question of whether the risk data is accurate.</span>"},
{"id":"D1-058","domain":1,"obj":"1B5","diff":"hard","q":"An organization's board sets a low risk appetite for operational disruption, but IT management routinely accepts risks that would breach that appetite without escalation. What is the risk practitioner's BEST recommendation?","options":["Allow IT management to continue making these decisions since they understand technical details best","Remove the risk appetite statement since it is not being followed","Establish a formal risk acceptance and escalation process requiring board or delegated authority approval for exceptions to appetite","Transfer all operational risk to a third-party insurer to avoid the issue"],"answer":2,"explain":"<strong>Establish a formal risk acceptance and escalation process requiring board or delegated authority approval for exceptions to appetite</strong> — a defined process ensures decisions that would exceed the board's appetite are properly escalated and approved at the appropriate level, restoring governance control.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Allow IT management to continue making these decisions since they understand technical details best</b>: technical expertise does not confer authority to override the board-approved risk appetite.</span> <span class='qd'><b>Remove the risk appetite statement since it is not being followed</b>: removing the standard eliminates the very control needed to hold decisions accountable, rather than fixing the enforcement gap.</span> <span class='qd'><b>Transfer all operational risk to a third-party insurer to avoid the issue</b>: insurance does not address the governance failure of bypassing escalation for appetite breaches.</span>"},
{"id":"D1-059","domain":1,"obj":"1B6","diff":"med","q":"Which of the following BEST describes how COBIT's governance and management objectives relate to IT risk?","options":["They are only applicable to financial reporting risk","They eliminate the need for a separate risk register","They provide a structured set of processes and practices that can be used to design and evaluate IT risk governance","They apply only to organizations with an internal audit function"],"answer":2,"explain":"<strong>They provide a structured set of processes and practices that can be used to design and evaluate IT risk governance</strong> — COBIT's governance and management objectives offer a comprehensive structure that organizations can use to design, assess, and improve IT-related governance, including risk.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>They are only applicable to financial reporting risk</b>: COBIT addresses IT governance broadly, not solely financial reporting concerns.</span> <span class='qd'><b>They eliminate the need for a separate risk register</b>: COBIT provides structure for governance processes; it does not replace the need to document specific risks in a register.</span> <span class='qd'><b>They apply only to organizations with an internal audit function</b>: COBIT is applicable to any organization seeking to govern IT effectively, regardless of whether it has internal audit.</span>"},
{"id":"D1-060","domain":1,"obj":"1B7","diff":"easy","q":"Which of the following is the PRIMARY risk of failing to track changes in applicable laws and regulations affecting IT operations?","options":["The organization's stock price will decline immediately","IT staff turnover will increase","The organization may unknowingly fall out of compliance and face legal or financial consequences","Software licensing costs will rise"],"answer":2,"explain":"<strong>The organization may unknowingly fall out of compliance and face legal or financial consequences</strong> — without monitoring regulatory change, the organization risks operating in violation of new requirements, exposing itself to penalties and legal action.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The organization's stock price will decline immediately</b>: stock price is influenced by many factors and does not automatically or immediately reflect regulatory tracking gaps.</span> <span class='qd'><b>IT staff turnover will increase</b>: staff turnover is not a direct or primary consequence of failing to track regulatory changes.</span> <span class='qd'><b>Software licensing costs will rise</b>: licensing costs are unrelated to whether legal and regulatory changes are being tracked.</span>"},
{"id":"D1-061","domain":1,"obj":"1B8","diff":"med","q":"A CEO wants to reduce board meeting time by removing IT risk as a standing agenda item and instead handling it only when a major incident occurs. What is the BEST response from the risk practitioner?","options":["Agree immediately since incidents are rare","Suggest replacing board reporting with a monthly email newsletter instead","Recommend the change since IT risk is a purely operational matter","Recommend retaining regular reporting since ongoing oversight, not just incident-driven review, is a core governance responsibility"],"answer":3,"explain":"<strong>Recommend retaining regular reporting since ongoing oversight, not just incident-driven review, is a core governance responsibility</strong> — governance requires continuous oversight of risk exposure and trends, not only reactive attention after something goes wrong.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Agree immediately since incidents are rare</b>: rarity of incidents does not reduce the board's ongoing accountability for risk oversight.</span> <span class='qd'><b>Suggest replacing board reporting with a monthly email newsletter instead</b>: an informal newsletter lacks the governance rigor and engagement of formal board-level reporting and discussion.</span> <span class='qd'><b>Recommend the change since IT risk is a purely operational matter</b>: IT risk has enterprise-level strategic implications and is not purely operational, warranting board attention.</span>"},
{"id":"D1-062","domain":1,"obj":"1A1","diff":"med","q":"Which of the following would BEST help an information risk practitioner demonstrate that the IT risk strategy supports the organization's business strategy?","options":["A list of every risk management certification held by staff","The total number of hours spent in risk committee meetings","A comparison of risk spending against competitors' spending","A documented mapping showing how each major risk initiative supports a specific business objective"],"answer":3,"explain":"<strong>A documented mapping showing how each major risk initiative supports a specific business objective</strong> — explicit traceability between risk initiatives and business objectives is the clearest evidence of strategic alignment.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A list of every risk management certification held by staff</b>: certifications reflect competence but do not demonstrate strategic alignment.</span> <span class='qd'><b>The total number of hours spent in risk committee meetings</b>: meeting time is an input measure with no bearing on strategic alignment.</span> <span class='qd'><b>A comparison of risk spending against competitors' spending</b>: competitor benchmarking is a secondary reference, not evidence of internal strategic alignment.</span>"},
{"id":"D1-063","domain":1,"obj":"1A2","diff":"easy","q":"Which of the following organizational features BEST enables timely escalation of significant IT risk issues to the board?","options":["A policy that forbids discussing risk outside scheduled quarterly meetings","An organizational chart that is never updated","A requirement that only the CEO may ever mention risk to the board","A defined escalation threshold and reporting path from operational teams through management to the board"],"answer":3,"explain":"<strong>A defined escalation threshold and reporting path from operational teams through management to the board</strong> — clear thresholds and pathways ensure that significant issues reach the board promptly rather than being delayed or lost in ambiguity.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A policy that forbids discussing risk outside scheduled quarterly meetings</b>: restricting discussion to quarterly meetings would delay urgent escalations rather than enable timeliness.</span> <span class='qd'><b>An organizational chart that is never updated</b>: a stale chart does not reflect current reporting relationships and would hinder, not help, escalation.</span> <span class='qd'><b>A requirement that only the CEO may ever mention risk to the board</b>: funneling all risk communication through one person creates a bottleneck rather than enabling timely escalation.</span>"},
{"id":"D1-064","domain":1,"obj":"1A3","diff":"med","q":"Which of the following BEST reflects a well-designed accountability structure for IT risk within an organization?","options":["Every employee is equally accountable for every risk","Accountability shifts automatically to whoever most recently worked on the related system","No one is accountable until a risk is realized as an incident","Every risk has a single accountable owner, even where multiple parties are responsible for supporting tasks"],"answer":3,"explain":"<strong>Every risk has a single accountable owner, even where multiple parties are responsible for supporting tasks</strong> — good accountability design assigns one clear accountable party per risk, even though several people may share responsibility for the underlying activities.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Every employee is equally accountable for every risk</b>: diffusing accountability across everyone equally in practice means no one is truly accountable.</span> <span class='qd'><b>Accountability shifts automatically to whoever most recently worked on the related system</b>: accountability should be deliberately assigned, not determined by incidental recent activity.</span> <span class='qd'><b>No one is accountable until a risk is realized as an incident</b>: accountability must exist proactively, before an incident occurs, not only in reaction to one.</span>"},
{"id":"D1-065","domain":1,"obj":"1A4","diff":"easy","q":"Which of the following actions by senior leadership would MOST strengthen a positive risk culture?","options":["Publicly criticizing employees who report problems","Basing all bonuses solely on speed of delivery","Discouraging any mention of risk in team meetings","Visibly supporting employees who raise early warning signs of risk, even when the news is unwelcome"],"answer":3,"explain":"<strong>Visibly supporting employees who raise early warning signs of risk, even when the news is unwelcome</strong> — leadership behavior that welcomes bad news models the openness and psychological safety needed for a strong, proactive risk culture.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Publicly criticizing employees who report problems</b>: punishing reporters discourages future disclosure and damages risk culture.</span> <span class='qd'><b>Basing all bonuses solely on speed of delivery</b>: an incentive ignoring risk considerations encourages corner-cutting rather than sound risk management.</span> <span class='qd'><b>Discouraging any mention of risk in team meetings</b>: suppressing risk conversation undermines transparency and awareness.</span>"},
{"id":"D1-066","domain":1,"obj":"1A5","diff":"hard","q":"An organization's risk policy requires annual review, but the review has been rubber-stamped without substantive changes for four consecutive years despite significant technology and regulatory shifts. What is the MOST significant concern?","options":["The policy document's file size has grown too large","The annual review meeting is scheduled at an inconvenient time","Staff will need to memorize the policy from a previous year","The review process itself may have become a formality that fails to identify needed updates to the policy"],"answer":3,"explain":"<strong>The review process itself may have become a formality that fails to identify needed updates to the policy</strong> — a review producing no substantive changes despite real environmental shifts suggests the process is not genuinely evaluating the policy's continued adequacy.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The policy document's file size has grown too large</b>: file size is a trivial technical detail unrelated to the substantive governance concern.</span> <span class='qd'><b>The annual review meeting is scheduled at an inconvenient time</b>: scheduling convenience does not address whether the review is substantively effective.</span> <span class='qd'><b>Staff will need to memorize the policy from a previous year</b>: memorization requirements are not the core issue; policy currency and relevance are.</span>"},
{"id":"D1-067","domain":1,"obj":"1A6","diff":"med","q":"Which of the following is the MOST important input when determining an organization's maximum tolerable downtime (MTD) for a critical application?","options":["The preferences of the application's development team","The original purchase cost of the application","The number of help desk tickets historically logged for the application","The business impact of extended unavailability as identified through the business impact analysis"],"answer":3,"explain":"<strong>The business impact of extended unavailability as identified through the business impact analysis</strong> — MTD should be grounded in how much disruption the business can actually tolerate before suffering unacceptable impact, which the BIA is designed to determine.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The preferences of the application's development team</b>: developer preference is not a reliable indicator of actual business tolerance for downtime.</span> <span class='qd'><b>The original purchase cost of the application</b>: acquisition cost does not reflect the business consequences of unavailability.</span> <span class='qd'><b>The number of help desk tickets historically logged for the application</b>: ticket volume reflects support demand, not business criticality or downtime tolerance.</span>"},
{"id":"D1-068","domain":1,"obj":"1A7","diff":"easy","q":"Which of the following BEST supports accurate risk assessment of IT assets across the enterprise?","options":["A list of assets purchased more than five years ago","An inventory maintained solely for depreciation and accounting purposes","A spreadsheet of assets that is updated only during litigation","A current, centrally maintained inventory that classifies assets by criticality and ownership"],"answer":3,"explain":"<strong>A current, centrally maintained inventory that classifies assets by criticality and ownership</strong> — accurate risk assessment depends on knowing what assets exist, their business criticality, and who owns them, all of which a well-maintained inventory provides.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A list of assets purchased more than five years ago</b>: an inventory limited to older assets misses current, actively used systems that also carry risk.</span> <span class='qd'><b>An inventory maintained solely for depreciation and accounting purposes</b>: an accounting-focused list may omit criticality and ownership details needed for risk assessment.</span> <span class='qd'><b>A spreadsheet of assets that is updated only during litigation</b>: infrequent, reactive updates leave the inventory stale for ongoing risk management purposes.</span>"},
{"id":"D1-069","domain":1,"obj":"1B1","diff":"med","q":"Which of the following is the MOST effective way to ensure IT risk is consistently considered as part of the organization's overall enterprise risk management activities?","options":["Have the IT department manage its own risk register with no linkage to the ERM function","Report IT risk to the board only when specifically requested","Conduct IT risk assessments once every five years","Integrate IT risk assessment into the same governance cycle, tools, and reporting used for other enterprise risk categories"],"answer":3,"explain":"<strong>Integrate IT risk assessment into the same governance cycle, tools, and reporting used for other enterprise risk categories</strong> — using the same cadence, tools, and reporting lines as the rest of ERM ensures IT risk is consistently visible and considered alongside other enterprise risks.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Have the IT department manage its own risk register with no linkage to the ERM function</b>: an unlinked register creates a silo that undermines enterprise-wide integration.</span> <span class='qd'><b>Report IT risk to the board only when specifically requested</b>: ad hoc reporting undermines the ongoing, proactive oversight ERM requires.</span> <span class='qd'><b>Conduct IT risk assessments once every five years</b>: a five-year cycle is far too infrequent to keep pace with a changing risk environment.</span>"},
{"id":"D1-070","domain":1,"obj":"1B2","diff":"hard","q":"An enterprise risk committee wants IT risk data included in its quarterly reporting, but the IT risk register uses a five-point qualitative scale while the enterprise register uses a monetary loss exposure model. What should the risk practitioner recommend?","options":["Continue reporting both scales separately with no reconciliation, since they measure different things","Develop a mapping or conversion approach so IT risk data can be meaningfully compared within the enterprise model","Discontinue IT risk reporting until IT adopts a monetary model without any transition support","Replace the enterprise register's monetary model with the IT department's qualitative scale unilaterally"],"answer":1,"explain":"<strong>Develop a mapping or conversion approach so IT risk data can be meaningfully compared within the enterprise model</strong> — creating a bridge between the two scales allows IT risk to be integrated and compared meaningfully within the enterprise risk reporting model, supporting sound aggregation.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Continue reporting both scales separately with no reconciliation, since they measure different things</b>: reporting separately without reconciliation prevents the committee from getting a unified view of enterprise exposure.</span> <span class='qd'><b>Discontinue IT risk reporting until IT adopts a monetary model without any transition support</b>: halting reporting removes visibility into IT risk altogether, which is counterproductive to governance.</span> <span class='qd'><b>Replace the enterprise register's monetary model with the IT department's qualitative scale unilaterally</b>: unilaterally changing the enterprise-wide model to suit one department disregards the needs of other risk categories already using it.</span>"},
{"id":"D1-071","domain":1,"obj":"1B3","diff":"med","q":"Which of the following situations BEST illustrates a violation of the three lines of defense model?","options":["Internal audit reviewing controls designed and operated by IT operations","A risk management function setting policy that the business must follow","Internal audit personnel also performing daily control operation and remediation for the units they audit","Business unit management implementing controls recommended by the risk management function"],"answer":2,"explain":"<strong>Internal audit personnel also performing daily control operation and remediation for the units they audit</strong> — when the third line performs first-line operational duties for the same areas it is meant to independently assess, it compromises the independence the model is built on.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Internal audit reviewing controls designed and operated by IT operations</b>: this is the normal, appropriate function of the third line assessing the first line.</span> <span class='qd'><b>A risk management function setting policy that the business must follow</b>: this reflects the expected second-line role of establishing frameworks for the first line to follow.</span> <span class='qd'><b>Business unit management implementing controls recommended by the risk management function</b>: this is a normal, appropriate interaction between the first and second lines.</span>"},
{"id":"D1-072","domain":1,"obj":"1B4","diff":"easy","q":"Which of the following would MOST directly change an organization's overall risk profile?","options":["A routine password reset campaign for all employees","A scheduled software patch applied without incident","An update to the corporate holiday calendar","The identification of a new significant risk following the launch of a major new IT system"],"answer":3,"explain":"<strong>The identification of a new significant risk following the launch of a major new IT system</strong> — a newly identified significant risk directly adds to the aggregate exposure the organization faces, changing the overall risk profile.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A routine password reset campaign for all employees</b>: a standard, uneventful password reset does not represent a material shift in risk exposure.</span> <span class='qd'><b>A scheduled software patch applied without incident</b>: a successful, routine patch does not itself introduce a new or changed risk to the profile.</span> <span class='qd'><b>An update to the corporate holiday calendar</b>: this administrative change has no bearing on the organization's risk exposure.</span>"},
{"id":"D1-073","domain":1,"obj":"1B5","diff":"med","q":"An organization defines its risk tolerance for system downtime as no more than four hours per critical incident. A recent incident caused six hours of downtime, though it remained within the board's overall risk appetite for the year. What should happen NEXT?","options":["Take no further action since the annual appetite was not breached","Immediately raise the risk appetite to cover future similar incidents","Remove the downtime tolerance metric from future reporting","Investigate the tolerance breach and report findings to the appropriate governance body, even though appetite was not exceeded"],"answer":3,"explain":"<strong>Investigate the tolerance breach and report findings to the appropriate governance body, even though appetite was not exceeded</strong> — a tolerance breach on a specific metric is a meaningful signal that warrants investigation and reporting, regardless of whether the broader annual appetite was exceeded.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Take no further action since the annual appetite was not breached</b>: ignoring a tolerance breach misses an opportunity to address a specific control or capability gap.</span> <span class='qd'><b>Immediately raise the risk appetite to cover future similar incidents</b>: loosening the tolerance to accommodate poor performance masks the underlying issue rather than addressing it.</span> <span class='qd'><b>Remove the downtime tolerance metric from future reporting</b>: removing visibility into the metric prevents future monitoring of a real operational risk.</span>"},
{"id":"D1-074","domain":1,"obj":"1B6","diff":"easy","q":"Which of the following BEST describes the purpose of adopting a recognized risk governance framework such as COSO ERM or ISO 31000?","options":["To guarantee compliance with every possible regulation automatically","To eliminate the need for a risk appetite statement","To replace the role of the board in risk oversight","To provide a structured, consistent approach for embedding risk management into organizational governance and decision-making"],"answer":3,"explain":"<strong>To provide a structured, consistent approach for embedding risk management into organizational governance and decision-making</strong> — these frameworks offer proven structures for integrating risk considerations systematically into how the organization is governed and how decisions are made.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>To guarantee compliance with every possible regulation automatically</b>: no framework can guarantee automatic compliance with all applicable laws; frameworks support but do not replace compliance efforts.</span> <span class='qd'><b>To eliminate the need for a risk appetite statement</b>: these frameworks typically call for a risk appetite statement as a component, not something they remove the need for.</span> <span class='qd'><b>To replace the role of the board in risk oversight</b>: frameworks support the board's oversight role; they do not substitute for board accountability.</span>"},
{"id":"D1-075","domain":1,"obj":"1B7","diff":"med","q":"An organization's IT risk practitioner discovers a contractual clause with a key vendor that conflicts with the organization's own data protection standards. What is the BEST course of action?","options":["Ignore the clause since the contract has already been signed","Terminate the vendor relationship immediately without further analysis","Change the internal data protection standard to match the vendor's clause","Assess the risk this conflict creates and work with legal and procurement to renegotiate or remediate the clause"],"answer":3,"explain":"<strong>Assess the risk this conflict creates and work with legal and procurement to renegotiate or remediate the clause</strong> — evaluating the exposure and collaborating with the relevant functions to resolve the contractual conflict addresses the risk without an overreaction.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Ignore the clause since the contract has already been signed</b>: ignoring a known conflicting obligation leaves the organization exposed to ongoing risk.</span> <span class='qd'><b>Terminate the vendor relationship immediately without further analysis</b>: termination without analysis is a disproportionate response before understanding the actual risk and remediation options.</span> <span class='qd'><b>Change the internal data protection standard to match the vendor's clause</b>: lowering internal standards to accommodate a vendor's contract terms could increase organizational risk rather than manage it.</span>"},
{"id":"D1-076","domain":1,"obj":"1B8","diff":"med","q":"Which of the following BEST reflects appropriate board oversight of IT risk, as distinct from management's role?","options":["The board reviewing aggregated risk reports and approving risk appetite, while management executes day-to-day risk responses","The board personally configuring security tools","The board writing detailed technical remediation plans","The board performing the annual internal audit of IT controls"],"answer":0,"explain":"<strong>The board reviewing aggregated risk reports and approving risk appetite, while management executes day-to-day risk responses</strong> — this reflects the proper governance-management split: the board directs and oversees at a strategic level, while management carries out operational risk activities.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The board personally configuring security tools</b>: hands-on technical configuration is a management/operational task, not a board governance function.</span> <span class='qd'><b>The board writing detailed technical remediation plans</b>: detailed remediation planning is a management responsibility, not something the board itself should be doing.</span> <span class='qd'><b>The board performing the annual internal audit of IT controls</b>: performing the audit itself would compromise the board's oversight role and blur governance and assurance functions.</span>"},
{"id":"D1-077","domain":1,"obj":"1A1","diff":"easy","q":"An IT risk strategy that is properly aligned with enterprise strategy should PRIMARILY result in:","options":["Risk management activities that directly support the achievement of business objectives within acceptable risk levels","A strategy document that never requires updates","Complete avoidance of all IT-related risk","A strategy developed solely by the IT department without business input"],"answer":0,"explain":"<strong>Risk management activities that directly support the achievement of business objectives within acceptable risk levels</strong> — proper alignment means risk activities are purposefully directed at enabling business goals while keeping exposure within accepted limits.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A strategy document that never requires updates</b>: a well-aligned strategy still requires periodic updates as business and risk conditions evolve.</span> <span class='qd'><b>Complete avoidance of all IT-related risk</b>: avoiding all risk is neither feasible nor an appropriate goal of a risk-aligned strategy.</span> <span class='qd'><b>A strategy developed solely by the IT department without business input</b>: excluding business input would undermine, not achieve, alignment with enterprise strategy.</span>"},
{"id":"D1-078","domain":1,"obj":"1A2","diff":"med","q":"Which of the following organizational design choices would MOST likely improve the speed and quality of enterprise IT risk decisions?","options":["Establishing a cross-functional risk committee with clear decision rights and executive sponsorship","Requiring every decision to be approved by the full board regardless of significance","Eliminating all committees in favor of individual departmental decision-making","Assigning risk decisions to whichever manager is available at the time"],"answer":0,"explain":"<strong>Establishing a cross-functional risk committee with clear decision rights and executive sponsorship</strong> — a properly empowered committee with defined authority brings together the right perspectives and can make timely, well-informed risk decisions.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Requiring every decision to be approved by the full board regardless of significance</b>: routing all decisions through the board regardless of materiality would slow decision-making rather than improve it.</span> <span class='qd'><b>Eliminating all committees in favor of individual departmental decision-making</b>: purely siloed decisions lose the cross-functional perspective needed for balanced enterprise risk decisions.</span> <span class='qd'><b>Assigning risk decisions to whichever manager is available at the time</b>: ad hoc assignment lacks the consistency and expertise needed for quality decision-making.</span>"},
{"id":"D1-079","domain":1,"obj":"1A3","diff":"hard","q":"A risk practitioner is documenting accountability for a newly outsourced IT function. The vendor will perform daily operations, but who remains accountable for the risk associated with that function?","options":["The organization retains accountability, even though operational responsibility has been outsourced","The vendor becomes solely accountable once the contract is signed","Accountability transfers entirely to the vendor's regulator","No one is accountable since the function is now external"],"answer":0,"explain":"<strong>The organization retains accountability, even though operational responsibility has been outsourced</strong> — outsourcing can transfer operational tasks, but accountability for the risk and its outcomes remains with the organization that owns the business relationship and its customers.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The vendor becomes solely accountable once the contract is signed</b>: a vendor can be contractually responsible for performance, but the client organization cannot fully transfer away its own accountability.</span> <span class='qd'><b>Accountability transfers entirely to the vendor's regulator</b>: regulators oversee compliance but do not assume the organization's internal risk accountability.</span> <span class='qd'><b>No one is accountable since the function is now external</b>: outsourcing never eliminates accountability; it changes who performs the work, not who is ultimately answerable for outcomes.</span>"},
{"id":"D1-080","domain":1,"obj":"1A4","diff":"med","q":"Which of the following would BEST help an organization assess the current state of its risk culture?","options":["Conducting surveys and interviews to gauge how employees perceive and act on risk in daily decisions","Reviewing only the number of security awareness emails sent","Counting the number of risk management certifications held by leadership","Reviewing the total IT budget allocated to security tools"],"answer":0,"explain":"<strong>Conducting surveys and interviews to gauge how employees perceive and act on risk in daily decisions</strong> — direct measurement of attitudes and behaviors through surveys and interviews provides genuine insight into how risk is actually valued and acted upon day to day.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Reviewing only the number of security awareness emails sent</b>: email volume measures communication output, not actual cultural attitudes or behavior.</span> <span class='qd'><b>Counting the number of risk management certifications held by leadership</b>: certifications reflect individual knowledge, not the broader organizational culture around risk.</span> <span class='qd'><b>Reviewing the total IT budget allocated to security tools</b>: spending levels do not directly indicate how risk is perceived or acted on by staff.</span>"},
{"id":"D1-081","domain":1,"obj":"1A5","diff":"med","q":"Which of the following BEST supports enforceability of an organization's IT risk policy?","options":["Defined consequences for noncompliance communicated alongside the policy and consistently applied","A policy that is long and highly detailed","A policy written exclusively in technical jargon","A policy that is reviewed only by the legal department"],"answer":0,"explain":"<strong>Defined consequences for noncompliance communicated alongside the policy and consistently applied</strong> — clear, consistently applied consequences give the policy teeth and reinforce that adherence is expected and monitored.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A policy that is long and highly detailed</b>: length and detail do not by themselves make a policy enforceable; clarity and consequence do.</span> <span class='qd'><b>A policy written exclusively in technical jargon</b>: jargon-heavy language actually reduces understanding and compliance across the broader workforce.</span> <span class='qd'><b>A policy that is reviewed only by the legal department</b>: legal review alone does not establish the consequences needed to enforce compliance.</span>"},
{"id":"D1-082","domain":1,"obj":"1A6","diff":"hard","q":"A risk practitioner finds that the disaster recovery plan for a critical application has not been tested in three years, though it is reviewed and re-approved annually on paper. What is the GREATEST concern?","options":["The plan's actual effectiveness during a real disruption remains unverified despite formal approval","The plan will need to be reformatted for the next review cycle","Annual re-approval requires too much administrative time","The plan document is stored in an outdated file format"],"answer":0,"explain":"<strong>The plan's actual effectiveness during a real disruption remains unverified despite formal approval</strong> — paper approval without testing does not confirm the plan will actually work; only testing validates whether recovery objectives can genuinely be met.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The plan will need to be reformatted for the next review cycle</b>: formatting is a cosmetic detail, not the substantive risk concern.</span> <span class='qd'><b>Annual re-approval requires too much administrative time</b>: administrative burden is a minor issue compared to the untested reliability of the plan itself.</span> <span class='qd'><b>The plan document is stored in an outdated file format</b>: file format has no bearing on whether the recovery plan will actually function as intended.</span>"},
{"id":"D1-083","domain":1,"obj":"1A7","diff":"med","q":"Which of the following would MOST improve the accuracy of risk assessments that depend on asset criticality ratings?","options":["Involving business process owners in validating and periodically updating asset criticality classifications","Allowing IT alone to assign criticality ratings without business input","Using the same criticality rating for all assets to simplify analysis","Assigning criticality ratings only once, at the time an asset is first purchased"],"answer":0,"explain":"<strong>Involving business process owners in validating and periodically updating asset criticality classifications</strong> — business owners best understand how critical an asset is to their operations, and their ongoing involvement keeps classifications accurate as needs change.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Allowing IT alone to assign criticality ratings without business input</b>: IT may lack full visibility into the business impact of an asset, risking misclassification.</span> <span class='qd'><b>Using the same criticality rating for all assets to simplify analysis</b>: uniform ratings ignore genuine differences in asset importance and impair prioritization.</span> <span class='qd'><b>Assigning criticality ratings only once, at the time an asset is first purchased</b>: criticality can change over time as business use evolves, so a one-time rating quickly becomes inaccurate.</span>"},
{"id":"D1-084","domain":1,"obj":"1B1","diff":"med","q":"Which of the following is the BEST evidence that an organization has a mature enterprise risk management program covering IT risk?","options":["Risk information from across the enterprise, including IT, is consistently aggregated, prioritized, and used to inform strategic decisions","The organization has purchased ERM software","IT risk assessments are performed but never shared outside the IT department","The organization has never experienced a security incident"],"answer":0,"explain":"<strong>Risk information from across the enterprise, including IT, is consistently aggregated, prioritized, and used to inform strategic decisions</strong> — maturity is demonstrated by risk information actually informing strategic decision-making across the enterprise, not merely being collected.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The organization has purchased ERM software</b>: owning a tool does not equate to a mature program if the underlying processes and integration are weak.</span> <span class='qd'><b>IT risk assessments are performed but never shared outside the IT department</b>: siloed assessments that never reach enterprise decision-makers indicate immaturity, not maturity.</span> <span class='qd'><b>The organization has never experienced a security incident</b>: absence of incidents may reflect luck or narrow scope rather than genuine program maturity.</span>"},
{"id":"D1-085","domain":1,"obj":"1B2","diff":"easy","q":"Which of the following BEST reflects effective alignment between IT risk management and the broader enterprise risk management function?","options":["IT risk findings are incorporated into the enterprise-wide risk register and reviewed using consistent criteria","IT risk is reported using a completely different taxonomy from all other enterprise risks","IT risk management operates under a separate charter with no connection to enterprise risk policy","IT risk is only discussed during IT department meetings"],"answer":0,"explain":"<strong>IT risk findings are incorporated into the enterprise-wide risk register and reviewed using consistent criteria</strong> — feeding IT risk into the same register and applying consistent evaluation criteria is a clear sign of genuine alignment with enterprise risk management.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>IT risk is reported using a completely different taxonomy from all other enterprise risks</b>: a mismatched taxonomy prevents meaningful comparison and undermines alignment.</span> <span class='qd'><b>IT risk management operates under a separate charter with no connection to enterprise risk policy</b>: an unconnected charter reflects a siloed, not aligned, approach.</span> <span class='qd'><b>IT risk is only discussed during IT department meetings</b>: confining discussion to IT-only forums keeps enterprise leadership uninformed, the opposite of alignment.</span>"},
{"id":"D1-086","domain":1,"obj":"1B3","diff":"med","q":"A company's second-line risk function has not challenged any first-line risk assessment in over two years, consistently approving every submission without question. What is the MOST likely governance concern?","options":["The second line may not be providing meaningful independent challenge, undermining the value of the three lines model","The first line has become extremely skilled at risk assessment","The third line will no longer need to perform audits","Risk assessments are taking too long to complete"],"answer":0,"explain":"<strong>The second line may not be providing meaningful independent challenge, undermining the value of the three lines model</strong> — a pattern of rubber-stamp approval suggests the second line is not genuinely scrutinizing first-line assessments, weakening the oversight the model depends on.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The first line has become extremely skilled at risk assessment</b>: this is an unsupported and overly generous assumption; a lack of challenge more plausibly signals a control weakness.</span> <span class='qd'><b>The third line will no longer need to perform audits</b>: the third line's assurance role remains necessary regardless of second-line performance.</span> <span class='qd'><b>Risk assessments are taking too long to complete</b>: this scenario does not describe a timing issue; it describes a lack of substantive challenge.</span>"},
{"id":"D1-087","domain":1,"obj":"1B4","diff":"hard","q":"An organization's risk profile shows overall exposure trending downward, but one emerging technology risk category is trending sharply upward and is not yet reflected in the risk appetite discussion. What should the risk practitioner do?","options":["Highlight the emerging risk category specifically to governance, even though the aggregate trend looks favorable","Report only the favorable aggregate trend to avoid alarming the board","Wait until the emerging risk exceeds appetite before reporting it","Merge the emerging risk category into an existing category to simplify reporting"],"answer":0,"explain":"<strong>Highlight the emerging risk category specifically to governance, even though the aggregate trend looks favorable</strong> — an aggregate improvement can mask a specific, rapidly growing risk; surfacing it separately ensures governance has visibility before it becomes a bigger problem.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Report only the favorable aggregate trend to avoid alarming the board</b>: omitting the emerging risk hides important information the board needs for informed oversight.</span> <span class='qd'><b>Wait until the emerging risk exceeds appetite before reporting it</b>: waiting until a breach occurs is reactive and defeats the purpose of early risk visibility.</span> <span class='qd'><b>Merge the emerging risk category into an existing category to simplify reporting</b>: merging categories could obscure the specific trend that governance needs to see clearly.</span>"},
{"id":"D1-088","domain":1,"obj":"1B5","diff":"easy","q":"Which of the following BEST describes the purpose of setting risk tolerance levels for specific objectives?","options":["To define acceptable variation around a specific objective within the broader risk appetite","To eliminate the need for a risk appetite statement","To set the total insurance coverage required","To determine which employees can access which systems"],"answer":0,"explain":"<strong>To define acceptable variation around a specific objective within the broader risk appetite</strong> — tolerance levels operationalize the broader appetite by specifying how much deviation is acceptable for a given metric or objective.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>To eliminate the need for a risk appetite statement</b>: tolerance works alongside, and depends on, an existing risk appetite statement rather than replacing it.</span> <span class='qd'><b>To set the total insurance coverage required</b>: insurance coverage decisions are a separate risk transfer activity, not the purpose of tolerance setting.</span> <span class='qd'><b>To determine which employees can access which systems</b>: access control decisions are an operational security matter, distinct from setting risk tolerance.</span>"},
{"id":"D1-089","domain":1,"obj":"1B6","diff":"med","q":"An organization wants to benchmark its IT risk governance maturity against a recognized capability model. Which of the following would be MOST appropriate to use?","options":["A capability maturity framework designed to assess governance and management process maturity, such as COBIT's maturity/capability model","A project schedule template","A network topology diagram","A customer satisfaction survey"],"answer":0,"explain":"<strong>A capability maturity framework designed to assess governance and management process maturity, such as COBIT's maturity/capability model</strong> — a purpose-built maturity model provides a structured, comparable way to assess how mature the organization's governance and management processes are.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A project schedule template</b>: a schedule template addresses project timing, not governance maturity assessment.</span> <span class='qd'><b>A network topology diagram</b>: a topology diagram documents technical architecture, not governance capability.</span> <span class='qd'><b>A customer satisfaction survey</b>: customer satisfaction measures an unrelated outcome, not internal governance maturity.</span>"},
{"id":"D1-090","domain":1,"obj":"1B7","diff":"med","q":"Which of the following BEST supports an organization's ability to respond to new legal or regulatory requirements affecting IT risk in a timely manner?","options":["A formal process for monitoring the regulatory environment and routing changes to risk and compliance stakeholders","Relying on employees to mention new laws they happen to hear about","Reviewing regulatory changes only during the annual external audit","Assuming existing controls will automatically cover any new requirement"],"answer":0,"explain":"<strong>A formal process for monitoring the regulatory environment and routing changes to risk and compliance stakeholders</strong> — a structured monitoring process ensures relevant regulatory developments are identified and routed promptly to those who must act on them.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Relying on employees to mention new laws they happen to hear about</b>: informal, incidental awareness is unreliable and likely to miss important changes.</span> <span class='qd'><b>Reviewing regulatory changes only during the annual external audit</b>: an annual-only review creates long windows where new obligations go unaddressed.</span> <span class='qd'><b>Assuming existing controls will automatically cover any new requirement</b>: assuming coverage without verification risks a compliance gap going undetected.</span>"},
{"id":"D1-091","domain":1,"obj":"1B8","diff":"hard","q":"A board of directors approves an aggressive digital transformation strategy but delegates all associated IT risk oversight entirely to a mid-level IT manager with no further reporting back to the board. What is the GREATEST governance weakness in this arrangement?","options":["The board lacks a mechanism to monitor whether the strategy's risk remains within its own approved appetite","The IT manager is likely to lack technical skill for the role","The digital transformation strategy will automatically fail","Mid-level managers are legally prohibited from managing risk"],"answer":0,"explain":"<strong>The board lacks a mechanism to monitor whether the strategy's risk remains within its own approved appetite</strong> — without reporting back to the board, there is no way for the board to fulfill its oversight duty and confirm that risk from the strategy stays within the appetite it approved.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The IT manager is likely to lack technical skill for the role</b>: the scenario does not indicate a competence issue; the concern is the missing oversight loop back to the board.</span> <span class='qd'><b>The digital transformation strategy will automatically fail</b>: a governance gap does not guarantee project failure; it creates unmanaged risk exposure.</span> <span class='qd'><b>Mid-level managers are legally prohibited from managing risk</b>: there is no such prohibition; delegation of operational risk management is normal and appropriate, but board accountability remains.</span>"},
{"id":"D1-092","domain":1,"obj":"1A1","diff":"med","q":"A risk practitioner is asked to update the IT risk strategy after the organization enters a new market with different regulatory requirements. Which step is MOST important before finalizing the updated strategy?","options":["Assess how the new market's regulatory and risk landscape affects the organization's overall risk appetite and objectives","Translate the existing strategy document into the new market's primary language only","Hire additional IT staff in the new market before any risk analysis","Postpone the update until the following year's budget cycle"],"answer":0,"explain":"<strong>Assess how the new market's regulatory and risk landscape affects the organization's overall risk appetite and objectives</strong> — entering a new market can introduce different risks and obligations, so understanding their impact on appetite and objectives is essential before updating strategy.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Translate the existing strategy document into the new market's primary language only</b>: translation alone does not address whether the strategy's substance is still appropriate for the new context.</span> <span class='qd'><b>Hire additional IT staff in the new market before any risk analysis</b>: staffing decisions should follow, not precede, an understanding of the new risk landscape.</span> <span class='qd'><b>Postpone the update until the following year's budget cycle</b>: delaying the update leaves the strategy misaligned with the new market's risks in the interim.</span>"},
{"id":"D1-093","domain":1,"obj":"1A2","diff":"easy","q":"Which of the following is the MOST effective way to ensure IT risk governance structures keep pace with organizational growth?","options":["Periodically reassessing reporting lines, committee membership, and escalation paths as the organization changes","Keeping the original governance structure unchanged regardless of organizational size","Removing all governance structures once the organization becomes large","Assigning governance responsibilities randomly among available staff"],"answer":0,"explain":"<strong>Periodically reassessing reporting lines, committee membership, and escalation paths as the organization changes</strong> — governance structures must evolve as the organization grows in size and complexity to remain effective and relevant.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Keeping the original governance structure unchanged regardless of organizational size</b>: a static structure is unlikely to remain adequate as complexity and scale increase.</span> <span class='qd'><b>Removing all governance structures once the organization becomes large</b>: larger organizations generally need more, not less, formal governance structure.</span> <span class='qd'><b>Assigning governance responsibilities randomly among available staff</b>: random assignment undermines the clarity and expertise governance structures are meant to provide.</span>"},
{"id":"D1-094","domain":1,"obj":"1A3","diff":"med","q":"Which of the following is the MOST important reason to formally document risk roles and responsibilities rather than relying on informal understanding?","options":["Formal documentation ensures consistent accountability that persists through staff turnover and organizational change","Formal documentation is required to satisfy printing vendor contracts","Informal understanding is always more accurate than documentation","Documentation eliminates the need for any future risk training"],"answer":0,"explain":"<strong>Formal documentation ensures consistent accountability that persists through staff turnover and organizational change</strong> — written roles and responsibilities remain stable and enforceable even as individuals move on, unlike informal or tacit understandings.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Formal documentation is required to satisfy printing vendor contracts</b>: this is an irrelevant and fabricated reason unrelated to actual governance needs.</span> <span class='qd'><b>Informal understanding is always more accurate than documentation</b>: informal understanding is typically less reliable and consistent than documented roles, not more accurate.</span> <span class='qd'><b>Documentation eliminates the need for any future risk training</b>: documentation supports training but does not remove the ongoing need to educate staff.</span>"},
{"id":"D1-095","domain":1,"obj":"1A4","diff":"med","q":"Which of the following would be the STRONGEST indicator that an organization's risk culture needs improvement?","options":["Risk incidents are frequently traced back to known issues that were never escalated due to fear of blame","Employees regularly participate in voluntary risk awareness training","Risk metrics are reviewed monthly by the risk committee","Business units routinely self-report minor control gaps for remediation"],"answer":0,"explain":"<strong>Risk incidents are frequently traced back to known issues that were never escalated due to fear of blame</strong> — recurring incidents rooted in known but unreported issues, driven by fear of blame, is a strong sign that the risk culture discourages open communication.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Employees regularly participate in voluntary risk awareness training</b>: voluntary engagement in training is a positive sign of risk culture, not a concern.</span> <span class='qd'><b>Risk metrics are reviewed monthly by the risk committee</b>: regular metric review reflects active governance engagement, a positive indicator.</span> <span class='qd'><b>Business units routinely self-report minor control gaps for remediation</b>: proactive self-reporting is a hallmark of a healthy, transparent risk culture.</span>"},
{"id":"D1-096","domain":1,"obj":"1A5","diff":"easy","q":"Which of the following BEST ensures that IT risk standards derived from policy remain practical and effective?","options":["Involving operational stakeholders in developing and periodically reviewing the standards","Drafting standards exclusively at the executive level with no operational input","Copying another organization's standards without adaptation","Publishing standards without any review after initial release"],"answer":0,"explain":"<strong>Involving operational stakeholders in developing and periodically reviewing the standards</strong> — those who operate under the standards daily can help ensure they are realistic, workable, and effective, and their ongoing input keeps standards relevant.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Drafting standards exclusively at the executive level with no operational input</b>: executives may lack the operational detail needed to create practical, workable standards.</span> <span class='qd'><b>Copying another organization's standards without adaptation</b>: standards from a different organization may not fit this organization's specific risks, culture, or environment.</span> <span class='qd'><b>Publishing standards without any review after initial release</b>: lack of ongoing review allows standards to become outdated and impractical over time.</span>"},
{"id":"D1-097","domain":1,"obj":"1A6","diff":"med","q":"Which of the following BEST supports the ongoing effectiveness of a business continuity plan?","options":["Regular testing, lessons-learned reviews, and updates reflecting changes in the business and IT environment","Writing the plan once during the initial project rollout and archiving it","Limiting plan knowledge to a single employee for confidentiality","Avoiding any changes to the plan to maintain consistency"],"answer":0,"explain":"<strong>Regular testing, lessons-learned reviews, and updates reflecting changes in the business and IT environment</strong> — ongoing testing and revision ensure the plan remains workable and relevant as the organization and its risks evolve.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>Writing the plan once during the initial project rollout and archiving it</b>: a plan that is never revisited will not reflect subsequent changes to systems, processes, or personnel.</span> <span class='qd'><b>Limiting plan knowledge to a single employee for confidentiality</b>: restricting knowledge to one person creates a single point of failure during an actual disruption.</span> <span class='qd'><b>Avoiding any changes to the plan to maintain consistency</b>: refusing to update the plan despite environmental changes undermines its practical effectiveness.</span>"},
{"id":"D1-098","domain":1,"obj":"1A7","diff":"hard","q":"An organization's risk practitioner finds that decommissioned servers are still listed as active in the asset inventory, and several still have production data accessible on them. What is the GREATEST risk this represents?","options":["Unmanaged, forgotten assets may retain sensitive data and controls while falling outside active risk oversight","The organization will need to purchase replacement hardware sooner than planned","IT support tickets related to those servers will increase","The organization's depreciation schedule will require adjustment"],"answer":0,"explain":"<strong>Unmanaged, forgotten assets may retain sensitive data and controls while falling outside active risk oversight</strong> — inaccurate inventory records mean these systems are effectively invisible to risk assessment and control monitoring, even though they may still hold sensitive data and pose real exposure.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The organization will need to purchase replacement hardware sooner than planned</b>: this is a minor procurement consideration, not the core governance risk of forgotten, unmanaged assets.</span> <span class='qd'><b>IT support tickets related to those servers will increase</b>: decommissioned, unmanaged servers are unlikely to generate active support demand.</span> <span class='qd'><b>The organization's depreciation schedule will require adjustment</b>: accounting depreciation is a financial administrative matter, not the primary risk concern here.</span>"},
{"id":"D1-099","domain":1,"obj":"1B4","diff":"med","q":"Which of the following would BEST help senior management interpret changes in the organization's aggregate risk profile over time?","options":["A dashboard trending key risk indicators and residual risk levels against the approved risk appetite","A single static snapshot of risks taken two years ago","An unstructured list of every risk ever identified, regardless of status","A report listing only risks that have been fully closed"],"answer":0,"explain":"<strong>A dashboard trending key risk indicators and residual risk levels against the approved risk appetite</strong> — a trending dashboard referenced against approved appetite gives management clear, actionable insight into how exposure is changing over time.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>A single static snapshot of risks taken two years ago</b>: an old, one-time snapshot cannot show how the risk profile has changed since then.</span> <span class='qd'><b>An unstructured list of every risk ever identified, regardless of status</b>: an unfiltered list without status or trend context is difficult to interpret and act upon.</span> <span class='qd'><b>A report listing only risks that have been fully closed</b>: closed risks alone omit the current, active exposure that matters most to ongoing oversight.</span>"},
{"id":"D1-100","domain":1,"obj":"1B8","diff":"hard","q":"An organization's board approves a new enterprise risk appetite statement, but no mechanism exists to translate it into operational risk tolerances that IT management can apply day to day. What is the MOST significant governance gap this creates?","options":["The disconnect between board-level direction and operational execution undermines the practical effectiveness of governance","The risk appetite statement will need to be printed in a larger font","IT management will have too much free time","The board will need to meet more frequently regardless of content"],"answer":0,"explain":"<strong>The disconnect between board-level direction and operational execution undermines the practical effectiveness of governance</strong> — governance direction only has value if it is operationalized; without a mechanism to translate appetite into actionable tolerances, management cannot apply the board's intent in daily decisions.<br><span class='qwhy'>Why the other options are wrong:</span> <span class='qd'><b>The risk appetite statement will need to be printed in a larger font</b>: formatting is irrelevant to the substantive governance-to-management translation gap.</span> <span class='qd'><b>IT management will have too much free time</b>: this is an implausible and irrelevant outcome, not a governance concern.</span> <span class='qd'><b>The board will need to meet more frequently regardless of content</b>: meeting frequency is not the fix for a missing translation mechanism between appetite and operational tolerances.</span>"},
]);
